const fs = require('fs');
const path = require('path');

function fixFile(filePath) {
    let content = fs.readFileSync(filePath, 'utf8');

    // Sequence for ├ô: C3 93 inside a UTF-8 file being shown as C3 81 and C3 A2 or something?
    // Actually if it's UTF-8, ├ô is C3 93. If I see ├üÔÇ£, it's literal C3 81 and E2 80 9C (in UTF8)

    const fixes = [
        { from: /├üÔÇ£/g, to: '├ô' },
        { from: /├üÔÇ░/g, to: '├ë' },
        { from: /├ü\u00ad/g, to: '├ì' },
        { from: /├ü\u00a0/g, to: '├ü' },
        { from: /├ü┬║/g, to: '├Ü' },
        { from: /├ü┬▒/g, to: '├▒' },
        { from: /├ü\u00a1/g, to: '├í' },
        { from: /├ü\u00a9/g, to: '├®' },
        { from: /├ü\/g, to: '├¡' }, // risky
        { from: /├ü┬│/g, to: '├│' },
        { from: /├ü┬║/g, to: '├║' },
        { from: /├é┬░/g, to: '┬░' },
        { from: /├óÔÇØÔé¼/g, to: 'ÔöÇ' },
        // Specific combos seen in hex
        { from: /T├ü\u0081CTICO/g, to: 'T├üCTICO' }, // C3 81 C2 81
        { from: /P├ü GINA/g, to: 'P├üGINA' },
        { from: /T├ü CTICO/g, to: 'T├üCTICO' },
        { from: /INSTALACI├üÔÇ£N/g, to: 'INSTALACI├ôN' },
        { from: /EMISI├üÔÇ£N/g, to: 'EMISI├ôN' },
        { from: /CONFIGURACI├üÔÇ£N/g, to: 'CONFIGURACI├ôN' },
        { from: /RELACI├üÔÇ£N/g, to: 'RELACI├ôN' },
        { from: /ATENCI├üÔÇ£N/g, to: 'ATENCI├ôN' },
        { from: /DIRECCI├üÔÇ£N/g, to: 'DIRECCI├ôN' },
        { from: /GESTI├üÔÇ£N/g, to: 'GESTI├ôN' },
        { from: /PROGRAMACI├üÔÇ£N/g, to: 'PROGRAMACI├ôN' },
        { from: /VERSI├üÔÇ£N/g, to: 'VERSI├ôN' },
        { from: /REPORTE T├ü CTICO/g, to: 'REPORTE T├üCTICO' },
        { from: /DETALLES T├üÔÇ░CNICOS/g, to: 'DETALLES T├ëCNICOS' },
        { from: /C├üÔÇ░DULA/g, to: 'C├ëDULA' },
        { from: /D├ü AS/g, to: 'D├ìAS' },
        { from: /T├üÔÇ░CNICO/g, to: 'T├ëCNICO' },
        { from: /S├ü\u0081B/g, to: 'S├üB' },
        { from: /M├ü\u0081S/g, to: 'M├üS' },
        { from: /V├é┬░B├é┬░/g, to: 'V┬░B┬░' },
    ];

    fixes.forEach(f => {
        content = content.split(f.from).join(f.to);
    });

    fs.writeFileSync(filePath, content, 'utf8');
    console.log(`Fixed ${filePath}`);
}

const files = [
    path.join(__dirname, 'src', 'pages', 'GestionPuestos.tsx'),
    path.join(__dirname, 'src', 'pages', 'Resumen.tsx'),
    path.join(__dirname, 'src', 'App.tsx'),
    path.join(__dirname, 'src', 'components', 'layout', 'Sidebar.tsx')
];

files.forEach(f => {
    if (fs.existsSync(f)) {
        fixFile(f);
    }
});

// CORAZA CTA - Tactical Logic Core

import React, { Suspense, lazy, useState, useEffect, useCallback } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { useAuthStore } from './store/authStore';
import { useSupabaseInit } from './hooks/useSupabaseInit';
import { useMotorInteligencia } from './store/useMotorInteligencia';
import Login from './pages/Login';
import AppLayout from './components/layout/AppLayout';
import ErrorBoundary from './components/ErrorBoundary';

// Optimized Lazy Loading for all pages
const Dashboard = lazy(() => import('./pages/Dashboard'));
const Vigilantes = lazy(() => import('./pages/Vigilantes'));
const MapaPuestos = lazy(() => import('./pages/Puestos'));
const GestionPuestos = lazy(() => import('./pages/GestionPuestos'));
const Inteligencia = lazy(() => import('./pages/Inteligencia'));
const Novedades = lazy(() => import('./pages/Novedades'));
const Resumen = lazy(() => import('./pages/Resumen'));
const Auditoria = lazy(() => import('./pages/AuditoriaInterna'));
const Configuracion = lazy(() => import('./pages/Configuracion'));

// Lightweight spinner for page transitions (Suspense fallback)
const PageLoader = () => (
  <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
    <div className="relative size-12">
      <div className="absolute inset-0 border-4 border-primary/20 rounded-full" />
      <div className="absolute inset-0 border-4 border-t-primary rounded-full animate-spin" />
    </div>
    <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Cargando m├│dulo...</p>
  </div>
);

// Full-screen blocking loader (only for auth/initial load)
const TacticalLoading = ({ onBypass, logs }: { onBypass?: () => void, logs?: string[] }) => (
  <div className="flex-1 flex flex-col items-center justify-center min-h-[100vh] space-y-8 bg-[#050A14] text-white p-6 overflow-hidden relative">
    {/* Fondo tactico */}
    <div className="absolute inset-0 opacity-10 bg-[radial-gradient(circle_at_center,_#4318FF_0%,_transparent_70%)]"></div>
    <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.03)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.03)_1px,transparent_1px)] bg-[size:40px_40px] [mask-image:radial-gradient(ellipse_at_center,black,transparent_80%)]"></div>

    <div className="relative">
      <div className="size-24 rounded-2xl border-2 border-[#4318FF]/30 flex items-center justify-center animate-pulse shadow-[0_0_30px_rgba(67,24,255,0.2)]">
        <div className="size-16 border-4 border-[#4318FF] rounded-full border-t-transparent animate-spin"></div>
      </div>
      <div className="absolute -top-1 -right-1 size-4 bg-[#30D158] rounded-full animate-ping"></div>
    </div>

    <div className="text-center space-y-3 relative z-10 max-w-sm">
      <h2 className="text-xl font-black tracking-[0.2em] uppercase text-white drop-shadow-md">CUADRO OPERATIVO</h2>
      <p className="text-[10px] font-bold text-[#4318FF] uppercase tracking-[0.3em] opacity-80">Sincronizando con Servidores Coraza</p>

      {/* Logs tracking */}
      {logs && logs.length > 0 && (
        <div className="mt-6 p-4 bg-black/40 border border-white/10 rounded-xl text-left font-mono text-[9px] text-slate-400 space-y-1 max-h-32 overflow-y-auto custom-scrollbar">
          {logs.slice(-5).map((log, i) => (
            <div key={i} className="flex gap-2">
              <span className="text-[#4318FF]/70">[{new Date().toLocaleTimeString()}]</span>
              <span>{log}</span>
            </div>
          ))}
        </div>
      )}
    </div>

    {/* BOTON DE EMERGENCIA: SI SE QUEDA PEGADO MAS DE 6 SEGUNDOS */}
    {onBypass && (
      <button 
        onClick={onBypass}
        className="mt-12 px-8 py-3 bg-[#FF4B4B]/10 hover:bg-[#FF4B4B]/20 border border-[#FF4B4B]/30 text-[#FF4B4B] text-[10px] font-black uppercase tracking-[0.2em] rounded-xl transition-all animate-bounce"
      >
        ÔÜá´©Å FORZAR ARRANQUE (BYPASS)
      </button>
    )}
  </div>
);

const SupabaseDataLoader = ({ children, onFinish }: { children: React.ReactNode, onFinish: () => void }) => {
  const { isLoading, logs } = useSupabaseInit();

  useEffect(() => {
    if (!isLoading) onFinish();
  }, [isLoading, onFinish]);

  if (isLoading) {
    return <TacticalLoading logs={logs} />;
  }

  return <>{children}</>;
};

function App() {
  const { isAuthenticated, checkSession, loading, loginBypass } = useAuthStore();
  const [logs, setLogs] = useState<string[]>(['Nucleo iniciado.']);
  const [showFailsafe, setShowFailsafe] = useState(false);

  const addLog = useCallback((msg: string) => {
    console.log(`[CORAZA] ${msg}`);
    setLogs(prev => [...prev.slice(-50), msg]); // Keep logs manageable
  }, []);

  const handleSyncFinish = useCallback(() => {
    addLog('Datos sincronizados.');
  }, [addLog]);

  useEffect(() => {
    addLog('Verificando Sesion...');

    // Safety check for session
    const timeout = setTimeout(() => {
        if (loading) {
            addLog('Ôîø El servidor de sesion no responde. Activando Failsafe...');
            setShowFailsafe(true);
        }
    }, 6000);

    checkSession()
      .then(() => {
        addLog('Sesion verificada.');
        clearTimeout(timeout);
      })
      .catch((err) => {
        addLog('Error en sesion: ' + (err?.message || 'Error Desconocido'));
        clearTimeout(timeout);
      });

    return () => clearTimeout(timeout);
  }, []);

  // Protegido: solo funciona con el c├│digo de emergencia correcto
  const forceStart = () => {
    const code = prompt('C├│digo de emergencia:');
    const emergencyCode = import.meta.env.VITE_BYPASS_CODE || 'CORAZA-SOPORTE';
    if (code === emergencyCode) {
      addLog('­ƒöÑ FORZANDO ARRANQUE... Bypass autorizado.');
      loginBypass && loginBypass();
    } else {
      addLog('ÔØî C├│digo de bypass incorrecto. Acceso denegado.');
    }
  };

  if (loading && !showFailsafe) {
    return <TacticalLoading />;
  }

  if (loading && showFailsafe) {
    return <TacticalLoading onBypass={forceStart} logs={logs} />;
  }

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-[#050A14]">
        <Login />
      </div>
    );
  }

  return (
    <BrowserRouter>
      <Toaster position="top-right" />
      {/* LOAD DATA FROM SUPABASE + RUN THE AI ENGINE */}
      <SupabaseDataLoader onFinish={handleSyncFinish}>
        <ErrorBoundary>
          <AppContent />
        </ErrorBoundary>
      </SupabaseDataLoader>
    </BrowserRouter>
  );
}

const AppContent = () => {
  useMotorInteligencia(); // Run AI engine in background

  return (
    <Routes>
      <Route path="/" element={<AppLayout />}>
        <Route index element={<Suspense fallback={<PageLoader />}><Dashboard /></Suspense>} />
        <Route path="dashboard" element={<Suspense fallback={<PageLoader />}><Dashboard /></Suspense>} />
        <Route path="vigilantes" element={<Suspense fallback={<PageLoader />}><Vigilantes /></Suspense>} />
        <Route path="disponibles" element={<Suspense fallback={<PageLoader />}><Vigilantes defaultTab="reserva" /></Suspense>} />
        <Route path="puestos" element={<Suspense fallback={<PageLoader />}><MapaPuestos /></Suspense>} />
        <Route path="gestion-puestos" element={<Suspense fallback={<PageLoader />}><GestionPuestos /></Suspense>} />
        <Route path="inteligencia" element={<Suspense fallback={<PageLoader />}><Inteligencia /></Suspense>} />
        <Route path="novedades" element={<Suspense fallback={<PageLoader />}><Novedades /></Suspense>} />
        <Route path="configuracion" element={<Suspense fallback={<PageLoader />}><Configuracion /></Suspense>} />
        <Route path="config" element={<Navigate to="/configuracion" replace />} />
        <Route path="auditoria" element={<Suspense fallback={<PageLoader />}><Auditoria /></Suspense>} />
        <Route path="resumen" element={<Suspense fallback={<PageLoader />}><Resumen /></Suspense>} />
        <Route path="resumen/pdf" element={<Suspense fallback={<PageLoader />}><Resumen /></Suspense>} />
      </Route>
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
};

export default App;

// VERSION 2.1 - Cleaned and isolated EditCeldaModal component
import React, { useState } from 'react';
import { AsignacionPuesto, Vigilante, TurnoConfig, JornadaConfig } from '../types';

interface EditCeldaModalProps {
    asig: AsignacionPuesto;
    vigilantes: Array<{ id: string; dbId?: string; nombre: string; estado: string }>;
    titularesId: string[];
    ocupados: Map<string, string[]>;
    turnosConfig: TurnoConfig[];
    jornadasCustom: JornadaConfig[];
    onSave: (asig: AsignacionPuesto) => void;
    onClose: () => void;
}

const EditCeldaModal: React.FC<EditCeldaModalProps> = ({ asig, vigilantes, titularesId, ocupados, turnosConfig, jornadasCustom, onSave, onClose }) => {
    const [vigilanteId, setVigilanteId] = useState<string | null>(asig.vigilanteId);
    const [jornada, setJornada] = useState<string>(asig.jornada);
    const [error, setError] = useState<string | null>(null);

    const jornadasList = (jornadasCustom.length ? jornadasCustom : [
        { id: 'normal', nombre: 'Normal', short: 'N', color: '#4318FF' },
        { id: 'descanso_remunerado', nombre: 'Descanso Rem.', short: 'DR', color: '#10b981' },
        { id: 'descanso_no_remunerado', nombre: 'Descanso No R.', short: 'DNR', color: '#f59e0b' },
        { id: 'sin_asignar', nombre: 'Sin Asignar', short: '-', color: '#f1f5f9' },
    ]);

    const checkConflict = (vid: string | null, t: string) => {
        if (!vid) return null;
        const slots = ocupados.get(vid) || [];
        if (slots.includes(`${asig.dia}-${t}`)) {
            const v = vigilantes.find(gv => gv.id === vid || gv.dbId === vid);
            return `${v?.nombre || 'Efectivo'} ya tiene turno el dia ${asig.dia} (${t})`;
        }
        return null;
    };

    const handleSave = () => {
        const conflict = checkConflict(vigilanteId, asig.turno || 'AM');
        if (conflict) {
            setError(conflict);
            return;
        }
        onSave({ ...asig, vigilanteId, jornada });
    };

    const selectedVig = vigilantes.find(v => v.id === vigilanteId || v.dbId === vigilanteId);
    const jornadaActual = jornadasList.find(j => j.id === jornada) ?? jornadasList[0];

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/40 backdrop-blur-sm animate-in fade-in transition-all">
            <div className="bg-white max-w-lg w-full rounded-[32px] overflow-hidden shadow-[0_25px_80px_rgba(0,0,0,0.3)] border border-slate-100 flex flex-col md:flex-row animate-in zoom-in-95 duration-200">
                <div className="p-8 flex-1 space-y-6">
                    <div className="flex justify-between items-start mb-2">
                        <div>
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-2">Editor de Asignacion</p>
                            <h3 className="text-xl font-black text-slate-900 uppercase">DIA {asig.dia} - {asig.turno}</h3>
                        </div>
                        <button onClick={onClose} className="size-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-400 hover:bg-slate-200 transition-colors">
                            <span className="material-symbols-outlined text-[18px]">close</span>
                        </button>
                    </div>

                    {error && (
                        <div className="p-3 bg-red-50 border border-red-100 rounded-2xl flex items-center gap-2 text-red-600 animate-in slide-in-from-top-2">
                            <span className="material-symbols-outlined text-[18px]">error</span>
                            <span className="text-[11px] font-bold">{error}</span>
                        </div>
                    )}

                    <div className="space-y-4">
                        <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Personal Asignado</label>
                            <select
                                value={vigilanteId || ''}
                                onChange={e => { setVigilanteId(e.target.value || null); setError(null); }}
                                className="w-full h-12 bg-slate-50 border-2 border-slate-100 rounded-2xl px-4 text-sm font-bold text-slate-900 outline-none focus:border-primary/30 focus:bg-white transition-all shadow-sm"
                            >
                                <option value="">- Sin Vigilante -</option>
                                <optgroup label="TITULARES DEL PUESTO">
                                    {vigilantes.filter(v => titularesId.includes(v.id) || (v.dbId && titularesId.includes(v.dbId))).map(v => (
                                        <option key={v.id} value={v.id}>Ô¡É {v.nombre}</option>
                                    ))}
                                </optgroup>
                                <optgroup label="REEMPLAZOS / OTROS">
                                    {vigilantes.filter(v => !titularesId.includes(v.id) && !(v.dbId && titularesId.includes(v.dbId))).map(v => (
                                        <option key={v.id} value={v.id}>{v.nombre} ({v.estado})</option>
                                    ))}
                                </optgroup>
                            </select>
                        </div>

                        <div>
                            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Tipo de Jornada</label>
                            <div className="grid grid-cols-2 gap-2">
                                {jornadasList.map(j => (
                                    <button
                                        key={j.id}
                                        onClick={() => { setJornada(j.id); setError(null); }}
                                        className={`px-4 py-3 rounded-2xl border-2 transition-all flex items-center gap-3 ${jornada === j.id ? 'bg-primary/5 border-primary shadow-sm' : 'bg-slate-50 border-transparent hover:bg-white hover:border-slate-200'}`}
                                    >
                                        <div className="size-3 rounded-full shrink-0" style={{ background: j.color }} />
                                        <div className="text-left">
                                            <p className={`text-[11px] font-black uppercase ${jornada === j.id ? 'text-primary' : 'text-slate-600'}`}>{j.nombre}</p>
                                        </div>
                                    </button>
                                ))}
                            </div>
                        </div>
                    </div>

                    <div className="flex gap-3 pt-4">
                        <button onClick={onClose} className="flex-1 py-4 text-[11px] font-black text-slate-400 uppercase tracking-widest hover:bg-slate-50 rounded-2xl transition-all">Cancelar</button>
                        <button onClick={handleSave} className="flex-[2] py-4 bg-primary text-white text-[11px] font-black uppercase tracking-widest rounded-2xl shadow-lg shadow-primary/30 hover:brightness-110 active:scale-95 transition-all">Confirmar Cambios</button>
                    </div>
                </div>

                <div className="w-full md:w-56 bg-slate-50 p-8 border-t md:border-t-0 md:border-l border-slate-100">
                    <div className="space-y-6">
                        <div>
                            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-3">Vigilante Seleccionado</p>
                            <div className="aspect-square rounded-3xl bg-white border border-slate-100 flex items-center justify-center shadow-sm">
                                <span className="material-symbols-outlined text-[48px] text-slate-200">person</span>
                            </div>
                            <p className="mt-3 text-xs font-black text-slate-900 line-clamp-2 leading-tight">{selectedVig?.nombre || 'VACANTE'}</p>
                            <p className="text-[10px] font-bold text-slate-400 mt-1">{selectedVig?.estado || 'Sin asignar'}</p>
                        </div>
                        <div className="pt-4 border-t border-slate-200">
                            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-2">Turno & Jornada</p>
                            <div className="flex items-center gap-2">
                                <div className="px-2 py-1 rounded-md bg-white border border-slate-100 text-[10px] font-black text-slate-700">{asig.turno}</div>
                                <div className="px-2 py-1 rounded-md text-[10px] font-black text-white" style={{ background: jornadaActual.color }}>{jornadaActual.short}</div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default EditCeldaModal;

import { useEffect, useRef } from 'react';
import maplibre, { NavigationControl, Marker } from 'maplibre-gl';
import { usePuestoStore } from '../store/puestoStore';
import 'maplibre-gl/dist/maplibre-gl.css';

const MapLibreGL = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<maplibre.Map | null>(null);
  const markersRef = useRef<{ [id: string]: maplibre.Marker }>({});

  const puestos = usePuestoStore((state) => state.puestos);

  useEffect(() => {
    if (!mapContainer.current) return;

    const map = new maplibre.Map({
      container: mapContainer.current,
      style: 'https://basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json',
      center: [-75.5667, 6.2308], // Centrado en Medellin (Coraza CTA)
      zoom: 12.5,
      pitch: 45, // Angulo tactico
      bearing: -17
    });

    map.addControl(new NavigationControl({
      visualizePitch: true,
      showZoom: true,
      showCompass: true
    }), 'bottom-right');

    mapInstance.current = map;

    return () => {
      map.remove();
    };
  }, []);

  // Update markers when puestos data changes
  useEffect(() => {
    if (!mapInstance.current) return;

    const currentMap = mapInstance.current;

    // Create or update markers
    puestos.forEach(puesto => {
      if (!markersRef.current[puesto.id]) {
        // Create custom HTML element for marker
        const el = document.createElement('div');
        el.className = 'marker-tactical';
        el.innerHTML = `
                <div class="relative flex items-center justify-center group">
                    <div class="absolute w-8 h-8 rounded-full ${puesto.estado === 'alerta' ? 'bg-danger/20 animate-ping' : 'bg-primary/20'}"></div>
                    <div class="relative w-4 h-4 rounded-full border-[2px] border-white shadow-[0_0_10px_rgba(0,0,0,0.5)] ${puesto.estado === 'alerta' ? 'bg-danger' : 'bg-primary'}"></div>
                    
                    <div class="absolute bottom-full mb-2 opacity-0 group-hover:opacity-100 transition-opacity bg-black/80 backdrop-blur-md border border-white/10 text-white text-[10px] font-bold px-3 py-1.5 rounded-lg whitespace-nowrap shadow-xl pointer-events-none z-50">
                        <span class="text-primary tracking-widest block text-[8px] uppercase">${puesto.id}</span>
                        ${puesto.nombre}
                    </div>
                </div>
            `;

        const marker = new maplibre.Marker({ element: el })
          .setLngLat([puesto.lng, puesto.lat])
          .addTo(currentMap);

        markersRef.current[puesto.id] = marker;
      } else {
        // Update existing marker's position/color if needed
        const marker = markersRef.current[puesto.id];
        marker.setLngLat([puesto.lng, puesto.lat]);

        // Just replace the inner HTML to update color state
        marker.getElement().innerHTML = `
                <div class="relative flex items-center justify-center group">
                    <div class="absolute w-8 h-8 rounded-full ${puesto.estado === 'alerta' ? 'bg-danger/20 animate-ping' : 'bg-primary/20'}"></div>
                    <div class="relative w-4 h-4 rounded-full border-[2px] border-white shadow-[0_0_10px_rgba(0,0,0,0.5)] ${puesto.estado === 'alerta' ? 'bg-danger' : 'bg-primary'}"></div>
                    
                    <div class="absolute bottom-full mb-2 opacity-0 group-hover:opacity-100 transition-opacity bg-black/80 backdrop-blur-md border border-white/10 text-white text-[10px] font-bold px-3 py-1.5 rounded-lg whitespace-nowrap shadow-xl pointer-events-none z-50">
                        <span class="text-primary tracking-widest block text-[8px] uppercase">${puesto.id}</span>
                        ${puesto.nombre}
                    </div>
                </div>
            `;
      }
    });

    // Remove markers that are no longer in state
    Object.keys(markersRef.current).forEach(id => {
      if (!puestos.find(p => p.id === id)) {
        markersRef.current[id].remove();
        delete markersRef.current[id];
      }
    });

  }, [puestos]);

  return (
    <div className="relative w-full h-[400px] xl:h-full rounded-2xl overflow-hidden shadow-2xl">
      <div ref={mapContainer} className="h-full w-full" />
      {/* Capa tactica decorativa */}
      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_80px_rgba(0,0,0,0.5)] bg-gradient-to-b from-transparent via-transparent to-black/30" />

      {/* Bordes de escaneo */}
      <div className="absolute top-4 left-4 flex gap-2 pointer-events-none">
        <div className="px-3 py-1.5 rounded-xl bg-primary/20 border border-primary/40 text-[9px] font-black text-primary uppercase tracking-widest backdrop-blur-md shadow-[0_0_15px_rgba(67,24,255,0.2)]">Tactical Feed</div>
        <div className="px-3 py-1.5 rounded-xl bg-black/40 border border-white/10 text-[9px] font-black text-slate-300 uppercase tracking-widest backdrop-blur-md flex items-center gap-1.5 shadow-lg">
          <span className="w-1.5 h-1.5 bg-success rounded-full animate-pulse shadow-[0_0_5px_#05cd99]"></span>
          Active
        </div>
      </div>
    </div>
  );
};

