                setIsLoading(true);
                addLog('­ƒôª Conectando a Supabase...');

                // 1. CARGA CR├ìTICA (Vigilantes y Puestos en paralelo)
                // CORRECCI├ôN: Timeout reducido a 30s (era 180s = 3 minutos, inaceptable)
                addLog('­ƒº¼ Sincronizando DNA Operativo (Vigilantes y Puestos)...');
                const [vigRes, puestRes] = await Promise.allSettled([
                    Promise.race([
                        fetchVigilantes(),
                        new Promise((_, reject) => setTimeout(() => reject(new Error('Timeout Vigilantes')), 30000))
                    ]),
                    Promise.race([
                        fetchPuestos(),
                        new Promise((_, reject) => setTimeout(() => reject(new Error('Timeout Puestos')), 30000))
                    ])
                ]);

                if (vigRes.status === 'rejected') addLog('ÔÜá´©Å Vigilantes lentos, continuando con datos parciales...');
                else addLog('Ô£à Vigilantes Listos');

                if (puestRes.status === 'rejected') addLog('ÔÜá´©Å Puestos lentos, continuando con datos parciales...');
                else addLog('Ô£à Puestos Listos');

                // 2. CARGA DE PROGRAMACIONES
                // CORRECCI├ôN CR├ìTICA: Cargar programaciones DESPU├ëS de vigilantes y puestos.
                // El mapeo de IDs (shorthand MED-0001 ÔåÆ UUID) requiere que los puestos y vigilantes
                // est├®n en memoria. Si se cargan en paralelo, los calendarios aparecen vac├¡os
                // porque translatePuestoToUuid y translateFromDb no encuentran nada.
                addLog('­ƒôæ Recuperando Programaciones y Auditoria...');

                const now = new Date();
                const anio = now.getFullYear();
                const mesActual = now.getMonth();

                // Cargar mes anterior + actual + siguiente para navegaci├│n fluida
                const mesesACargar = [
                    { anio: mesActual === 0 ? anio - 1 : anio, mes: mesActual === 0 ? 11 : mesActual - 1 },
                    { anio, mes: mesActual },
                    { anio: mesActual === 11 ? anio + 1 : anio, mes: mesActual === 11 ? 0 : mesActual + 1 },
                ];

                const secondWave = await Promise.allSettled([
                    ...mesesACargar.map(m => fetchProgramacionesByMonth(m.anio, m.mes)),
                    fetchTemplates(),
                    fetchAudit(),
                ]);

                const waveSuccess = secondWave.filter(r => r.status === 'fulfilled').length;
                addLog(`­ƒÜÇ Sistema Listo (${waveSuccess}/${secondWave.length} m├│dulos operativos).`);
            } catch (err: any) {
                addLog('ÔÜá´©Å Alerta de Sistema: ' + (err.message || 'Error Desconocido'));
                console.error('[Coraza] ÔØî Error Critico:', err);
            } finally {
                setTimeout(() => setIsLoading(false), 500);
            }
        };

        initBaseDatos();
    }, []);

    return { isLoading, logs };
}

import { useCallback } from 'react';
import { usePuestoStore } from '../store/puestoStore';
import { useVigilanteStore } from '../store/vigilanteStore';
import toast from 'react-hot-toast';
import { showTacticalToast } from '../utils/tacticalToast';

/**
 * Custom hook to handle cross-store tactical operations
 * Ensuring data consistency between Puestos and Vigilantes
 */
export const useTacticalOps = () => {
    const { assignGuard: storeAssignGuard, removeGuard: storeRemoveGuard, updatePuestoStatus } = usePuestoStore();
    const { updateGuardStatus, addActivity } = useVigilanteStore();

    const assignGuardToPuesto = useCallback((puestoId: string, vigilanteId: string, horaInicio: string, horaFin: string) => {
        try {
            // 1. Update Puesto Store
            storeAssignGuard(puestoId, vigilanteId, horaInicio, horaFin);

            // 2. Update Vigilante Store
            updateGuardStatus(vigilanteId, 'activo', puestoId);

            // 3. Update Puesto Status if it was desprotegido (the Puesto page effect handles this too, but we can be proactive)
            // updatePuestoStatus(puestoId, 'cubierto');

            addActivity(vigilanteId, 'Asignacion Tactica', `Desplegado en puesto ${puestoId} (${horaInicio} - ${horaFin})`);
        } catch (error) {
            console.error('Error in tactical assignment:', error);
            showTacticalToast({
                title: 'Falla de Despliegue',
                message: 'No se pudo completar la asignacion tactica del efectivo.',
                type: 'error'
            });
        }
    }, [storeAssignGuard, updateGuardStatus, addActivity]);

    const removeGuardFromPuesto = useCallback((puestoId: string, vigilanteId: string, reason?: string) => {
        try {
            // 1. Update Puesto Store
            storeRemoveGuard(puestoId, vigilanteId, reason);

            // 2. Update Vigilante Store
            updateGuardStatus(vigilanteId, 'disponible', undefined, reason);

            addActivity(vigilanteId, 'Desvinculacion', reason || 'Removido del puesto operativo');
        } catch (error) {
            console.error('Error in tactical removal:', error);
            showTacticalToast({
                title: 'Error Operativo',
                message: 'La desvinculacion del efectivo ha fallado.',
                type: 'error'
            });
        }
    }, [storeRemoveGuard, updateGuardStatus, addActivity]);

    const togglePuestoAlert = useCallback((puestoId: string, currentStatus: string) => {
        const newStatus = currentStatus === 'alerta' ? 'cubierto' : 'alerta';
        updatePuestoStatus(puestoId, newStatus);

        if (newStatus === 'alerta') {
            showTacticalToast({
                title: 'Protocolo de Emergencia',
                message: `ALERTA ACTIVADA para el puesto ${puestoId}. Se requiere respuesta inmediata.`,
                type: 'error' // or 'warning', but 'error' is more red for emergency
            });
        } else {
            showTacticalToast({
                title: 'Situacion Controlada',
                message: `Puesto ${puestoId} normalizado. Amenaza neutralizada.`,
                type: 'success'
            });
        }
    }, [updatePuestoStatus]);

    return {
        assignGuardToPuesto,
        removeGuardFromPuesto,
        togglePuestoAlert
    };
};

