          >
            <span className="material-symbols-outlined text-primary group-hover:rotate-180 transition-transform">expand_more</span>
            <span className="text-sm font-black text-slate-700 uppercase tracking-widest">Cargar 100 puestos m├ís</span>
          </button>
        </div>
      )}
    </div>
  );
};

