    // Obtener alertas criticas reales desde el Motor de Inteligencia
    const iaAlertas = useMemo(() => 
        actions.filter(a => a.type === 'notification' && a.sender === 'ai' && (a.priority === 'high' || a.priority === 'medium')).reverse()
    , [actions]);

