                        <div className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase ${p.coberturaCompleta ? 'bg-success/10 text-success' : 'bg-warning/10 text-warning'}`}>
                            {p.coberturaCompleta ? 'Ô£ô Operativo' : 'ÔÜá´©Å Pendiente'}
                        </div>
                    </div>
                ))}
