import { toast } from 'react-hot-toast';
import { showTacticalToast } from '../utils/tacticalToast';
import { supabase, EMPRESA_ID } from '../lib/supabase';

export interface AIAction {
    id: string;
    text: string;
    timestamp: number;
    type: 'notification' | 'chat';
    sender: 'ai' | 'user';
    priority?: 'low' | 'medium' | 'high';
}

interface AIState {
    actions: AIAction[];
    isAnalyzing: boolean;
    isOpen: boolean;
    isMuted: boolean;
    unreadNotifications: number;
    addAction: (action: Omit<AIAction, 'id' | 'timestamp'>) => void;
    setAnalyzing: (val: boolean) => void;
    toggleOpen: () => void;
    toggleMute: () => void;
    clearUnread: () => void;
    clearChat: () => void;
    clearHistory: () => void;
}

export const useAIStore = create<AIState>()(
    persist(
        (set) => ({
            actions: [{
                id: 'init-msg',
                text: 'CorazAI Programador Iniciado. Estoy supervisando la integridad de toda la programacion y turnos del sistema.',
                timestamp: Date.now(),
                type: 'notification',
                sender: 'ai',
                priority: 'low'
            }],
            isAnalyzing: false,
            isOpen: false,
            isMuted: false,
            unreadNotifications: 1,
            addAction: (action) => set((state) => {
                const isFromAI = action.sender === 'ai';
                const isClosed = !state.isOpen;
                
                // Auto-determine priority if not provided
                let priority: AIAction['priority'] = action.priority || 'low';
                if (!action.priority) {
                    if (action.text.toLowerCase().includes('alerta') || action.text.toLowerCase().includes('critico') || action.text.toLowerCase().includes('atencion')) {
                        priority = 'high';
                    } else if (action.text.toLowerCase().includes('aviso') || action.text.toLowerCase().includes('revisar') || action.text.toLowerCase().includes('insight')) {
                        priority = 'medium';
                    }
                }

                if (isFromAI && isClosed && !state.isMuted) {
                    // --- SISTEMA DE NOTIFICACIONES FILTRADO POR RELEVANCIA ---
                    
                    // Solo enviamos WhatsApp automatico si es prioridad HIGH y viene del sistema
                    if (priority === 'high') {
                        const cleanMsg = action.text.replace(/\*\*(.*?)\*\*/g, '$1');
                        
                        // Disparo asincrono a Supabase Edge Function
                        supabase.functions.invoke('enviar-whatsapp', {
                            body: {
                                numero: '573113836939',
                                mensaje: `­ƒÜ¿ ALERTA CORAZAI: ${cleanMsg}`,
                                tipo_alerta: 'critica'
                            }
                        }).then(({ data, error }) => {
                            if (error) {
                                console.error('Error enviando WhatsApp automatico:', error);
                                // Notificacion discreta de fallo tecnico
                                showTacticalToast({
                                    title: 'Falla de Comunicaciones',
                                    message: 'Enlace WhatsApp interrumpido. Verifique Supabase Edge Functions.',
                                    type: 'error'
                                });
                            } else {
                                console.log('WhatsApp automatico enviado correctamente:', data);
                            }
                        });
                    }
                    
                    // 1. ALTA PRIORIDAD: Toast tactico expandido (Maxima visibilidad)
                    if (priority === 'high') {
                        let rawText = action.text.replace(/\*\*(.*?)\*\*/g, '$1');
                        showTacticalToast({
                            title: 'Protocolo Critico',
                            message: rawText,
                            type: 'ai',
                            duration: 10000,
                            action: {
                                label: 'Reportar WhatsApp',
                                href: `https://wa.me/573113836939?text=${encodeURIComponent(`­ƒÜ¿ ALERTA CORAZAI: ${rawText}`)}`
                            }
                        });
                    } 
                    // 2. MEDIA PRIORIDAD: Toast tactico refinado (Informativo pero premium)
                    else if (priority === 'medium') {
                        let rawText = action.text.replace(/\*\*(.*?)\*\*/g, '$1');
                        showTacticalToast({
                            title: 'Sugerencia Operativa',
                            message: rawText,
                            type: 'ai',
                            duration: 7000
                        });
                    }
                    // 3. BAJA PRIORIDAD: Silencioso (Solo badge en la campana)
                    // No hace nada, el usuario lo vera al abrir el panel o por el contador de Topbar.
                }

                // --- SYNC TO SUPABASE (NOVEDADES) ---
                if (isFromAI && priority !== 'low') {
                    const rawText = action.text.replace(/\*\*(.*?)\*\*/g, '$1');
                    supabase.from('novedades').insert({
                        empresa_id: EMPRESA_ID,
                        tipo: 'IA_INSIGHT',
                        titulo: priority === 'high' ? 'ALERTA CRITICA CORAZAI' : 'Aviso Operativo',
                        descripcion: rawText,
                        gravedad: priority === 'high' ? 'alta' : 'media',
                        estado: 'pendiente'
                    }).then(({ error }) => {
                        if (error) console.error('Error syncing AI novelty to Supabase:', error);
                    });
                }

                return {
                    actions: [...state.actions, {
                        ...action,
                        id: Math.random().toString(36).substr(2, 9),
                        timestamp: Date.now(),
                        priority
                    }],
                    unreadNotifications: (isClosed && isFromAI) ? state.unreadNotifications + 1 : state.unreadNotifications
                };
            }),
            setAnalyzing: (val) => set({ isAnalyzing: val }),
            toggleOpen: () => set((state) => ({
                isOpen: !state.isOpen,
                unreadNotifications: 0
            })),
            toggleMute: () => set((state) => ({ isMuted: !state.isMuted })),
            clearUnread: () => set({ unreadNotifications: 0 }),
            clearChat: () => set((state) => ({
                actions: state.actions.filter(a => a.type !== 'chat')
            })),
            clearHistory: () => set({
                actions: [{
                    id: 'init-msg-' + Date.now(),
                    text: 'Historial purgado. CorazAI Programador reinicializado. Monitoreando cuadrantes...',
                    timestamp: Date.now(),
                    type: 'notification',
                    sender: 'ai',
                    priority: 'low'
                }]
            })
        }),
        {
            name: 'coraza-ai-storage',
            storage: createJSONStorage(() => localStorage),
            partialize: (state) => ({ actions: state.actions }),
            onRehydrateStorage: () => (state) => {
                if (state) {
                    state.actions = state.actions || [];
                }
            }
        }
    )
);

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { supabase } from '../lib/supabase';

interface AuthState {
    isAuthenticated: boolean;
    username: string | null;
    role: string | null;
    userId: string | null;
    empresaId: string | null;
    loading: boolean;
    error: string | null;
    login: (email: string, password: string) => Promise<{ success: boolean; message?: string }>;
    logout: () => Promise<void>;
    updateProfile: (name: string, role: string, empresaId?: string) => void;
    checkSession: () => Promise<void>;
    loginBypass: () => void;
}

export const useAuthStore = create<AuthState>()(
    persist(
        (set, get) => ({
            isAuthenticated: false,
            username: null,
            role: null,
            userId: null,
            empresaId: null,
            loading: true,
            error: null,

            login: async (email, password) => {
                set({ loading: true, error: null });

                try {
                    const { data, error } = await supabase.auth.signInWithPassword({
                        email,
                        password,
                    });

                    if (error) {
                        set({ loading: false, error: error.message });
                        return { success: false, message: error.message };
                    }

                    if (!data.user) {
                        set({ loading: false, error: 'No se pudo obtener el usuario.' });
                        return { success: false, message: 'No se pudo obtener el usuario.' };
                    }

                    // Obtener perfil
                    const { data: profile } = await supabase
                        .from('usuarios')
                        .select('nombre_completo, rol, empresa_id')
                        .eq('id', data.user.id)
                        .single();

                    set({
                        isAuthenticated: true,
                        username: profile?.nombre_completo || data.user.email || 'Usuario',
                        role: profile?.rol || 'coordinador',
                        userId: data.user.id,
                        empresaId: profile?.empresa_id || 'a0000000-0000-0000-0000-000000000001',
                        loading: false,
                    });
                    return { success: true };
                } catch (err: any) {
                    const msg = err.message || 'Error de conexion desconocido';
                    set({ loading: false, error: msg });
                    return { success: false, message: msg };
                }
            },

            logout: async () => {
                try {
                    await supabase.auth.signOut();
                } catch { /* ignore */ }
                set({
                    isAuthenticated: false,
                    username: null,
                    role: null,
                    userId: null,
                    empresaId: null,
                    loading: false,
                    error: null,
                });
            },

            updateProfile: (username, role, empresaId) => set((s) => ({ 
                username, 
                role, 
                empresaId: empresaId || s.empresaId 
            })),

            checkSession: async () => {
                // Si ya tenemos una sesion v├ílida de Supabase, no la pises
                const current = get();
                if (current.isAuthenticated && current.userId && 
                    current.userId !== 'emergency-fix-id' && current.userId !== 'bypass-id') {
                    // Verificar que la sesi├│n de Supabase sigue vigente
                    try {
                        const { data: { session } } = await supabase.auth.getSession();
                        if (!session?.user) {
                            // Sesi├│n venida a menos, limpiar
                            set({ isAuthenticated: false, empresaId: null, loading: false });
                            return;
                        }
                        set({ loading: false });
                        return;
                    } catch {
                        set({ loading: false });
                        return;
                    }
                }

                // Sesiones de bypass siempre se mantienen
                if (current.isAuthenticated && (current.userId === 'emergency-fix-id' || current.userId === 'bypass-id')) {
                    set({ loading: false });
                    return;
                }

                try {
                    const { data: { session } } = await supabase.auth.getSession();
                    if (session?.user) {
                        const { data: profile } = await supabase
                            .from('usuarios')
                            .select('nombre_completo, rol, empresa_id')
                            .eq('id', session.user.id)
