// ÔöÇÔöÇ Private Helpers ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

const activeSyncPromises = new Map<string, Promise<SyncResult>>();
const pendingSyncs = new Map<string, any>();

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

const translateToUuid = (idRaw: string | null): string | null => {
    if (!idRaw) return null;
    const id = String(idRaw).trim();
    if (uuidRegex.test(id)) return id;

    // PERFORMANCE: Use Map from store if possible, or limited find for small sets
    const vStore = useVigilanteStore.getState();
    const v = vStore.vigilantes.find(vx => vx.id === id || vx.dbId === id);
    if (v?.dbId && uuidRegex.test(v.dbId)) return v.dbId;
    return null; 
};

const translateFromDb = (dbId: string | null, lookupMap?: Map<string, string>) => {
    if (!dbId) return null;
    if (lookupMap) return lookupMap.get(dbId) || dbId;
    const v = useVigilanteStore.getState().vigilantes.find((v: any) => v.dbId === dbId || v.id === dbId);
    return v?.id || dbId;
};

const translatePuestoToUuid = (idRaw: string | null): string | null => {
    if (!idRaw) return null;
    const id = String(idRaw).trim();
    if (uuidRegex.test(id)) return id;
    const p = usePuestoStore.getState().puestos.find((pt: any) => pt.id === id || pt.dbId === id);
    return p?.dbId || (uuidRegex.test(id) ? id : null);
};

const idsMatch = (id1: string | null, id2: string | null): boolean => {
    if (!id1 || !id2) return false;
    const str1 = String(id1).trim().toLowerCase();
    const str2 = String(id2).trim().toLowerCase();
    if (str1 === str2) return true;

    const vigilantes = useVigilanteStore.getState().vigilantes || [];
    const v1 = vigilantes.find((vx: any) => vx.id === id1 || vx.dbId === id1 || (vx.nombre && vx.nombre.toLowerCase() === str1));
    const v2 = vigilantes.find((vx: any) => vx.id === id2 || vx.dbId === id2 || (vx.nombre && vx.nombre.toLowerCase() === str2));

    if (v1 && v2) {
        return (v1.dbId === v2.dbId || v1.id === v2.id);
    }
    // Cross-match: check if one ID matches the other's property
    if (v1 && (v1.dbId === id2 || v1.id === id2)) return true;
    if (v2 && (v2.dbId === id1 || v2.id === id1)) return true;

    return false;
};

interface SyncResult {
    success: boolean;
    serverVersion: number;
    serverUpdatedAt: string | null;
}

async function syncProgramacionToDb(prog: ProgramacionMensual, set: any, get: any): Promise<SyncResult> {
    if (activeSyncPromises.has(prog.id)) {
        try { await activeSyncPromises.get(prog.id); } catch {}
    }

    const syncPromise = (async (): Promise<SyncResult> => {
        try {
            const dbId = String(prog.id).trim();
            const dbPuestoId = translatePuestoToUuid(prog.puestoId);
            if (!dbPuestoId) throw new Error("ID de puesto no encontrado");

            const currentEmpresaId = String(useAuthStore.getState().empresaId || EMPRESA_ID).trim();

            // PREPARAR PAYLOAD JSONB AT├ôMICO
            const asignacionesPayload = prog.asignaciones
                .filter(a => a.vigilanteId)
                .map(a => {
                    const mappedVid = translateToUuid(a.vigilanteId);
                    return mappedVid ? {
                        dia: a.dia,
                        vigilante_id: mappedVid,
                        turno: a.turno,
                        jornada: a.jornada,
                        rol: a.rol,
                        inicio: a.inicio || null,
                        fin: a.fin || null
                    } : null;
                })
                .filter(r => r !== null);

            const personalPayload = prog.personal
                .filter(p => p.vigilanteId)
                .map(p => {
                    const mappedVid = translateToUuid(p.vigilanteId);
                    return mappedVid ? { rol: p.rol, vigilante_id: mappedVid } : null;
                })
                .filter(p => p !== null);

            // LLAMADA AT├ôMICA AL RPC (Transacci├│n en Servidor)
            const { error: rpcErr } = await supabase.rpc('guardar_programacion_atomica', {
                p_prog_id: dbId,
                p_empresa_id: currentEmpresaId,
                p_puesto_id: dbPuestoId,
                p_anio: prog.anio,
                p_mes: prog.mes,
                p_estado: prog.estado,
                p_asignaciones: asignacionesPayload,
                p_personal: personalPayload
            });

            if (rpcErr) {
                console.error('[Coraza] ÔØî Fallo en Guardado At├│mico RPC:', rpcErr);
                throw new Error(`Servidor: ${rpcErr.message}`);
            }

            console.log(`[Coraza] ­ƒøí´©Å Sincronizaci├│n AT├ôMICA Exitosa: ${prog.id}`);
            return { success: true, serverVersion: (prog.version || 0) + 1, serverUpdatedAt: new Date().toISOString() };
        } catch (err: any) {
            console.error('[Coraza] ÔØî Error de Persistencia:', err);
            throw err;
        } finally {
            activeSyncPromises.delete(prog.id);
        }
    })();

    activeSyncPromises.set(prog.id, syncPromise);
    return syncPromise;
}

const queueSync = (progId: string, set: any, get: any, immediate = false) => {
    // CORRECCI├ôN A-5: Cancelar SIEMPRE el timeout pendiente, tanto para immediate como para debounce.
    // Esto previene el doble-sync donde immediate=true ejecuta inmediatamente Y el timeout
    // pendiente vuelve a ejecutar 1.2s despu├®s, causando dos escrituras a Supabase.
    if (pendingSyncs.has(progId)) {
        clearTimeout(pendingSyncs.get(progId)!);
        pendingSyncs.delete(progId);
    }

    const runSync = async () => {
        pendingSyncs.delete(progId);
        const prog = get().programaciones.find((p: any) => p.id === progId);
        if (!prog) return;
        // Evitar sync si ya hay uno activo para este progId
        if (activeSyncPromises.has(progId)) {
            // Reagendar para despu├®s de que el sync activo termine
            pendingSyncs.set(progId, setTimeout(runSync, 500));
            return;
        }
        set({ isSyncing: true });
        try {
            const res = await syncProgramacionToDb(prog, set, get);
            set((state: any) => ({
                programaciones: state.programaciones.map((p: any) => 
                    p.id === progId ? { ...p, syncStatus: 'synced' as const, version: res.serverVersion } : p
                ),
                isSyncing: false
            }));
        } catch (err: any) {
            console.error('[Coraza] ÔØî ERROR CR├ìTICO SYNCHRONIZACI├ôN:', err);
            set({ isSyncing: false, lastSyncError: err?.message || 'Error de escritura' });
            showTacticalToast({ 
                title: "ÔØî ERROR N├ÜCLEO", 
                message: `La base de datos rechaz├│ el despliegue: ${err?.message || 'Error desconocido'}`, 
                type: "error",
                duration: 8000
            });
        }
    };

    if (immediate) {
        runSync();
    } else {
        const timeout = setTimeout(runSync, 1200);
        pendingSyncs.set(progId, timeout);
    }
};

// ÔöÇÔöÇ Store Logic ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

export const useProgramacionStore = create<ProgramacionState>()(
    (set, get) => ({
            programaciones: [],
            templates: [],
            loaded: false,
            isSyncing: false,
            lastSyncError: null,
            selectedProgId: null,

            forceSync: async () => {
                set({ loaded: false });
                await get().fetchProgramaciones();
            },

            fetchProgramaciones: async () => {
                try {
                    set({ loaded: false });
                    const now = new Date();
                    const anio = now.getFullYear();
                    const mesActual = now.getMonth();

                    // CORRECCI├ôN: Cargar mes actual + mes anterior + mes siguiente
                    // para que la navegaci├│n del calendario funcione sin recargas
                    const meses = [
                        { anio: mesActual === 0 ? anio - 1 : anio, mes: mesActual === 0 ? 11 : mesActual - 1 },
                        { anio, mes: mesActual },
                        { anio: mesActual === 11 ? anio + 1 : anio, mes: mesActual === 11 ? 0 : mesActual + 1 },
                    ];
                    await Promise.all(meses.map(m => get().fetchProgramacionesByMonth(m.anio, m.mes)));
                } catch (error) {
                    console.error('[Coraza] ÔØî fetchProgramaciones Error:', error);
                    set({ loaded: true });
                }
            },

            fetchProgramacionesByMonth: async (anio: number, mes: number) => {
                try {
                    set({ loaded: false });

                    let allRows: any[] = [];
                    let from = 0;
                    const BATCH = 1000;

                    while (true) {
                        const { data, error } = await supabase
                            .from('programacion_mensual')
                            .select('*')
                            .eq('anio', anio)
                            .eq('mes', mes)
                            .range(from, from + BATCH - 1);

                        if (error) {
                            console.error('Error fetching prog batch:', error);
                            break;
                        }
                        if (!data || data.length === 0) break;

                        allRows = [...allRows, ...data];
                        from += BATCH;
                        if (allRows.length >= 7000) break;
                    }

                    const rows = allRows;

                    if (rows && rows.length > 0) {
                         const headers = rows.map(row => ({
                            id: row.id,
                            puestoId: row.puesto_id as string,
                            anio: row.anio,
                            mes: row.mes,
                            estado: row.estado as EstadoProgramacion as any,
                            creadoEn: row.created_at,
                            actualizadoEn: row.updated_at,
                            version: row.version || 1,
                            syncStatus: 'synced' as const,
                            personal: [],
                            asignaciones: [],
                            isDetailLoaded: false
                        }));

                        set((state: any) => {
                            const merged = [...state.programaciones];
                            headers.forEach(h => {
                                let idx = merged.findIndex(p => p.id === h.id);
                                if (idx < 0) {
                                    const dbUuid = translatePuestoToUuid(h.puestoId);
                                    idx = merged.findIndex(p => (p.puestoId === h.puestoId || p.puestoId === dbUuid) && p.anio === h.anio && p.mes === h.mes);
                                }

                                if (idx >= 0) {
                                    merged[idx] = { ...merged[idx], ...h };
                                } else {
                                    merged.push(h);
                                }
                            });

                            const newMap = new Map();
                            merged.forEach(p => {
                                newMap.set(`${p.puestoId}-${p.anio}-${p.mes}`, p);
                                newMap.set(p.id, p);
                            });

                            if (rows.length < 1000) {
                                setTimeout(() => get()._fetchDetails(rows, rows.map(r => r.id)), 100);
                            }

                            return { programaciones: merged, loaded: true, _progMap: newMap };
                        });
                    } else {
                        set({ loaded: true });
                    }
                } catch (err) {
                    console.error('[Coraza] ÔØî fetchProgramacionesByMonth Error:', err);
                    set({ loaded: true });
                }
            },

            fetchProgramacionDetalles: async (progId: string) => {
                try {
                    const prog = get().programaciones.find(p => p.id === progId);
                    const hasLocalData = prog && prog.asignaciones && prog.asignaciones.length > 0;
                    if (prog && ((prog as any).isDetailLoaded || hasLocalData)) {
                        if (!(prog as any).isDetailLoaded) {
                            set((state: any) => ({
                                programaciones: state.programaciones.map((p: any) => p.id === progId ? { ...p, isDetailLoaded: true } : p)
                            }));
                        }
                        return; // Ya cargado con datos locales reales
                    }

                    const [persRes, asigsRes] = await Promise.all([
                        supabase.from('personal_puesto').select('*').eq('programacion_id', progId),
                        supabase.from('asignaciones_dia').select('*').eq('programacion_id', progId).limit(200) // 93 max
                    ]);

                    if (persRes.error || asigsRes.error) {
                        console.error('[Laser Loading] ÔØî Fallo en red:', persRes.error || asigsRes.error);
                        return; // Abortamos para no sobreescribir con arrays vac├¡os por error de red
                    }

                    const personal = (persRes.data || []).map((p: any) => ({ 
                        rol: p.rol as RolPuesto, 
                        vigilanteId: translateFromDb(p.vigilante_id) 
                    }));

                    ['titular_a', 'titular_b', 'relevante'].forEach(rol => {
                        if (!personal.find(p => p.rol === rol)) personal.push({ rol, vigilanteId: null });
                    });

                    const asigMap = new Map();
                    (asigsRes.data || []).forEach((a: any) => {
                        asigMap.set(`${a.dia}-${a.rol}`, a);
                    });

                    const daysInMonth = new Date(prog?.anio || 2026, (prog?.mes || 0) + 1, 0).getDate();
                    const asignaciones: AsignacionDia[] = [];
                    const rolesToEnsure: RolPuesto[] = ['titular_a', 'titular_b', 'relevante'];

                    for (let d = 1; d <= daysInMonth; d++) {
                        rolesToEnsure.forEach(rol => {
                            const match = asigMap.get(`${d}-${rol}`);
                            if (match) {
                                asignaciones.push({
                                    dia: match.dia,
                                    vigilanteId: translateFromDb(match.vigilante_id),
                                    turno: match.turno,
                                    jornada: (match.jornada || 'sin_asignar') as TipoJornada,
                                    rol: (match.rol || rol) as RolPuesto,
                                    inicio: match.inicio || undefined,
                                    fin: match.fin || undefined
                                });
                            } else {
                                asignaciones.push({ dia: d, vigilanteId: null, turno: 'AM', jornada: 'sin_asignar', rol });
                            }
                        });
                    }

                    console.log(`[Laser Loading] Ô£à Datos reconstruidos para ${progId}: ${asignaciones.length} turnos.`);

                    const incomingHasData = asignaciones.some(a => a.vigilanteId !== null);

                    set((state: any) => ({
                        programaciones: state.programaciones.map((p: any) => {
                             if (p.id !== progId) return p;

                             const localIsPending = p.syncStatus === 'pending';
                             const localHasData = p.asignaciones && p.asignaciones.some((a: AsignacionDia) => a.vigilanteId !== null);

                             // REGLA DE CONFLICTO: Si hay trabajo local sin guardar, no dejamos que la DB lo pise
                             // a menos que la versi├│n de la DB sea mayor.
                             if (localIsPending) {
                                 const incomingVersion = (asignaciones.length > 0) ? (p.version || 1) : 0; // Aproximaci├│n
                                 // Nota: En fetching de un solo ID, row no est├í disponible aqu├¡ directamente, 
                                 // pero version suele estar en el objeto 'p'.
                                 return { ...p, isDetailLoaded: true }; // Mantenemos local
                             }

                             if (localHasData && !incomingHasData) {
                                 return { ...p, isDetailLoaded: true };
                             }

                             return {
                                 ...p,
                                 personal,
                                 asignaciones,
                                 isDetailLoaded: true
                             };
                        })
                    }));
                } catch (err) {
                    console.error('fetchProgramacionDetalles Error:', err);
                }
            },

            _fetchDetails: async (rows: any[], progIds: string[]) => {
                // CORRECCI├ôN C-5: Chunk reducido a 10 para evitar p├®rdida silenciosa de datos.
                // Con 20 progs ├ù 31 d├¡as ├ù 3 roles = 1860 asignaciones/chunk.
                // El l├¡mite de 5000 por query es insuficiente para chunks grandes.
                // Con 10 progs el m├íximo es 930, garantizando que limit(5000) siempre sea suficiente.
                const CHUNK_SIZE = 10; 
                let allPersonal: any[] = [];
                let allAsignaciones: any[] = [];

                console.log(`[Sync] ­ƒôÑ Descargando detalles en bloques de ${CHUNK_SIZE}...`);

                const chunkPromises = [];
                for (let i = 0; i < progIds.length; i += CHUNK_SIZE) {
                    const chunk = progIds.slice(i, i + CHUNK_SIZE);
                    chunkPromises.push(
                        Promise.all([
                            supabase.from('personal_puesto').select('*').in('programacion_id', chunk),
                            supabase.from('asignaciones_dia').select('*').in('programacion_id', chunk).limit(2000)
                        ])
                    );
                }

                const chunkResults = await Promise.all(chunkPromises);
                chunkResults.forEach(([persRes, asigsRes]) => {
                    if (persRes.data) allPersonal = [...allPersonal, ...persRes.data];
                    if (asigsRes.data) allAsignaciones = [...allAsignaciones, ...asigsRes.data];
                });

                console.log(`[Sync] ­ƒôè ${progIds.length} programaciones hidratadas en paralelo.`);

                // OPTIMIZACI├ôN CR├ìTICA: Pre-mapear vigilancia para evitar O(n^2) en la traducci├│n de IDs
                const currentVigilantes = useVigilanteStore.getState().vigilantes;
                const vigLookup = new Map<string, string>();
                currentVigilantes.forEach(v => {
                    if (v.dbId) vigLookup.set(v.dbId, v.id);
                    vigLookup.set(v.id, v.id);
                });

                // OPTIMIZACI├ôN: Pre-agrupar asignaciones por ID de programaci├│n para evitar filtrar 14k records en cada iteraci├│n
                const assignmentsByProgId = new Map<string, any[]>();
                allAsignaciones.forEach(a => {
                    if (!assignmentsByProgId.has(a.programacion_id)) assignmentsByProgId.set(a.programacion_id, []);
                    assignmentsByProgId.get(a.programacion_id)!.push(a);
                });

                const newProgramaciones: ProgramacionMensual[] = rows.map(row => {
                    const personal = allPersonal
                        .filter(p => p.programacion_id === row.id)
                        .map(p => ({ 
                            rol: p.rol as RolPuesto, 
                            vigilanteId: p.vigilante_id ? (vigLookup.get(p.vigilante_id) || p.vigilante_id) : null 
                        }));

                    ['titular_a', 'titular_b', 'relevante'].forEach(rol => {
                        if (!personal.find(p => p.rol === rol)) personal.push({ rol, vigilanteId: null });
                    });

                    const dbAsignaciones = assignmentsByProgId.get(row.id) || [];
                    const asigMap = new Map();
                    dbAsignaciones.forEach(a => {
                        const key = `${a.dia}-${a.rol}`;
                        asigMap.set(key, a);
                    });

                    const daysInMonth = new Date(row.anio, row.mes + 1, 0).getDate();
                    const asignaciones: AsignacionDia[] = [];
                    const rolesToEnsure: RolPuesto[] = ['titular_a', 'titular_b', 'relevante'];

                    for (let d = 1; d <= daysInMonth; d++) {
                        rolesToEnsure.forEach(rol => {
                            const match = asigMap.get(`${d}-${rol}`);
                            if (match) {
                                asignaciones.push({
                                    dia: match.dia,
                                    vigilanteId: match.vigilante_id ? (vigLookup.get(match.vigilante_id) || match.vigilante_id) : null,
                                    turno: match.turno,
                                    jornada: (match.jornada || 'sin_asignar') as TipoJornada,
                                    rol: (match.rol || rol) as RolPuesto,
                                    inicio: match.inicio || undefined,
                                    fin: match.fin || undefined
                                });
                            } else {
                                asignaciones.push({ dia: d, vigilanteId: null, turno: 'AM', jornada: 'sin_asignar', rol });
                            }
                        });
                    }

                    return {
                        id: row.id, puestoId: row.puesto_id as string, anio: row.anio, mes: row.mes,
                        personal, asignaciones, estado: row.estado as EstadoProgramacion,
                        creadoEn: row.created_at, actualizadoEn: row.updated_at,
                        version: row.version || 1, historialCambios: [], syncStatus: 'synced' as const
                    };
                });

                    set((state: any) => {
                        const merged = [...state.programaciones];
                        newProgramaciones.forEach(np => {
                            const idx = merged.findIndex(p => p.id === np.id);
                            if (idx >= 0) {
                                if (merged[idx].syncStatus === 'pending' && (np.version || 0) <= (merged[idx].version || 0)) {
                                    merged[idx].isDetailLoaded = true;
                                } else {
                                    merged[idx] = { ...merged[idx], ...np, isDetailLoaded: true };
                                }
                            } else {
                                merged.push({ ...np, isDetailLoaded: true });
                            }
                        });

                        // Recalculate full map for massive load
                        const newMap = new Map();
                        merged.forEach(p => {
                            newMap.set(`${p.puestoId}-${p.anio}-${p.mes}`, p);
                            newMap.set(p.id, p);
                        });

                        return { programaciones: merged, loaded: true, _progMap: newMap };
                    });
            },

            fetchTemplates: async () => {
                const currentEmpresaId = useAuthStore.getState().empresaId || EMPRESA_ID;
                const { data: rows } = await supabase.from('plantillas_programacion').select('*').eq('empresa_id', currentEmpresaId);
                if (rows) {
                    set({ templates: rows.map(r => ({
                        id: r.id, nombre: r.nombre, puestoId: r.puesto_id || '', puestoNombre: r.puesto_nombre || '',
                        personal: (r.personal as PersonalPuesto[]) || [], patron: (r.patron as any[]) || [],
                        creadoEn: r.created_at, creadoPor: r.creado_por || '',
                    })) });
                }
            },

            getProgramacion: (puestoId, anio, mes) => {
                return get().getProgramacionRapid(puestoId, anio, mes);
            },

            // USAR ESTE PARA RENDERING MASIVO (O(1))
            getProgramacionRapid: (puestoId: string, anio: number, mes: number) => {
                const dbUuid = translatePuestoToUuid(puestoId);
                const key1 = `${puestoId}-${anio}-${mes}`;
                const key2 = `${dbUuid}-${anio}-${mes}`;

                const state = get() as any;
                const map = state._progMap || new Map<string, any>();
                return map.get(key1) || map.get(key2) || undefined;
            },

            crearOObtenerProgramacion: (puestoId, anio, mes, usuario) => {
                const existing = get().getProgramacion(puestoId, anio, mes);
                if (existing) return existing;
                const dbPuestoId = translatePuestoToUuid(puestoId) || puestoId;
                const daysInMonth = new Date(anio, mes + 1, 0).getDate();
                const asignaciones: AsignacionDia[] = [];
                const roles: RolPuesto[] = ['titular_a', 'titular_b', 'relevante'];
                for (let dia = 1; dia <= daysInMonth; dia++) {
                    roles.forEach(rol => asignaciones.push({ dia, vigilanteId: null, turno: 'AM', jornada: 'sin_asignar', rol }));
                }
                // CORRECCI├ôN: Usar crypto.randomUUID() para generar UUID v4 v├ílido
                // Math.random() genera IDs no est├índar que el RPC de Supabase puede rechazar
                const newProg: ProgramacionMensual = {
                    id: crypto.randomUUID(),
                    puestoId: dbPuestoId, anio, mes,
                    personal: [{ rol: 'titular_a', vigilanteId: null }, { rol: 'titular_b', vigilanteId: null }, { rol: 'relevante', vigilanteId: null }],
                    asignaciones, estado: 'borrador', creadoEn: new Date().toISOString(), actualizadoEn: new Date().toISOString(),
                    version: 1, historialCambios: [], syncStatus: 'pending',
                    isDetailLoaded: true
                };
                set(s => ({ programaciones: [...s.programaciones, newProg] }));
                get()._updateMap();
                queueSync(newProg.id, set, get);
                return newProg;
            },

            asignarPersonal: (progId, personal, usuario) => {
                set(s => ({
                    programaciones: s.programaciones.map(p => p.id !== progId ? p : {
                        ...p, personal, actualizadoEn: new Date().toISOString(), syncStatus: 'pending'
                    })
                }));
                get()._updateMap();
                queueSync(progId, set, get, true);
            },

            actualizarAsignacion: (progId, dia, data, usuario) => {
                const prog = get().programaciones.find(p => p.id === progId);
                if (!prog) return { permitido: false, tipo: 'bloqueo', mensaje: 'Error: Programaci├│n no hallada' };

                // ÔöÇÔöÇ VALIDACI├ôN DE CONFLICTOS IA ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
                if (data.vigilanteId && data.jornada !== 'sin_asignar') {
                    const otrosConflictos = get().programaciones.some(p => 
                        p.id !== prog.id && p.anio === prog.anio && p.mes === prog.mes &&
                        p.asignaciones.some(a => a.dia === dia && idsMatch(a.vigilanteId, data.vigilanteId as string | null) && a.jornada !== 'sin_asignar')
                    );
                    if (otrosConflictos) return { permitido: false, tipo: 'bloqueo', mensaje: 'IA: El vigilante ya tiene una asignaci├│n en OTRO puesto hoy.' };
                }

                const newAsignaciones = [...prog.asignaciones];
                const idx = newAsignaciones.findIndex(a => a.dia === dia && a.rol === data.rol);
                if (idx >= 0) newAsignaciones[idx] = { ...newAsignaciones[idx], ...data };
                else newAsignaciones.push({ dia, vigilanteId: data.vigilanteId || null, turno: data.turno || 'AM', jornada: data.jornada || 'sin_asignar', rol: data.rol as string });

                set(s => ({
                    programaciones: s.programaciones.map(p => p.id === progId ? { ...p, asignaciones: newAsignaciones, actualizadoEn: new Date().toISOString(), syncStatus: 'pending' } : p)
                }));

                get()._updateMap();
                queueSync(progId, set, get, true);
                return { permitido: true, tipo: 'ok', mensaje: 'Asignaci├│n guardada' };
            },

            publicarProgramacion: (progId, usuario) => {
                set(s => ({
                    programaciones: s.programaciones.map(p => p.id !== progId ? p : { ...p, estado: 'publicado', syncStatus: 'pending' })
                }));
                queueSync(progId, set, get, true);
            },

            guardarBorrador: (progId, usuario) => {
                set(s => ({
                    programaciones: s.programaciones.map(p => p.id !== progId ? p : { ...p, estado: 'borrador', syncStatus: 'pending' })
                }));
                queueSync(progId, set, get, true);
            },

            guardarComoPlantilla: async (progId, nombre, puestoNombre, usuario) => {
                const prog = get().programaciones.find(p => p.id === progId);
                if (!prog) return;
                const template: TemplateProgramacion = {
                    id: crypto.randomUUID(), nombre, puestoId: prog.puestoId, puestoNombre,
                    personal: prog.personal.map(p => ({ ...p })),
                    patron: prog.asignaciones.map(a => ({ diaRelativo: a.dia, rol: a.rol, turno: a.turno, jornada: a.jornada, vigilanteId: a.vigilanteId })),
                    creadoEn: new Date().toISOString(), creadoPor: usuario,
                };
                set(s => ({ templates: [...s.templates, template] }));
                const currentEmpresaId = useAuthStore.getState().empresaId || EMPRESA_ID;
                await supabase.from('plantillas_programacion').insert({
                    id: template.id, empresa_id: currentEmpresaId, nombre, puesto_id: prog.puestoId,
                    puesto_nombre: puestoNombre, personal: template.personal, patron: template.patron, creado_por: usuario,
                });
            },

            aplicarPlantilla: (templateId, puestoId, anio, mes, usuario) => {
                const tpl = get().templates.find(t => t.id === templateId);
                if (!tpl) return;
                const prog = get().getProgramacion(puestoId, anio, mes);
                if (!prog) return;

                const newAsignaciones = prog.asignaciones.map(a => {
                    const match = tpl.patron.find(p => p.diaRelativo === a.dia && p.rol === a.rol);
                    return match ? { ...a, vigilanteId: match.vigilanteId, turno: match.turno, jornada: match.jornada } : a;
                });

                set(s => ({
                    programaciones: s.programaciones.map(p => p.id === prog.id ? { ...p, personal: tpl.personal, asignaciones: newAsignaciones, syncStatus: 'pending' } : p)
                }));
                queueSync(prog.id, set, get, true);
            },

            eliminarPlantilla: async (templateId) => {
                set(s => ({ templates: s.templates.filter(t => t.id !== templateId) }));
                await supabase.from('plantillas_programacion').delete().eq('id', templateId);
            },

            getDiasTrabajoVigilante: (progId, vigilanteId) => {
                const prog = get().programaciones.find(p => p.id === progId);
                if (!prog) return 0;
                return prog.asignaciones.filter(a => idsMatch(a.vigilanteId, vigilanteId) && (a.jornada !== 'sin_asignar')).length;
            },

            getDiasDescansoVigilante: (progId, vigilanteId) => {
                const prog = get().programaciones.find(p => p.id === progId);
                if (!prog) return { remunerados: 0, noRemunerados: 0 };
                const as = prog.asignaciones.filter(a => idsMatch(a.vigilanteId, vigilanteId));
                return { 
                    remunerados: as.filter(a => a.jornada === 'descanso_remunerado').length, 
                    noRemunerados: as.filter(a => a.jornada === 'descanso_no_remunerado').length 
                };
            },

            getCoberturaPorcentaje: (progId) => {
                const prog = get().programaciones.find(p => p.id === progId);
                if (!prog) return 0;
                const total = prog.asignaciones.length;
                const cubiertos = prog.asignaciones.filter(a => a.vigilanteId && a.jornada !== 'sin_asignar').length;
                return total === 0 ? 0 : Math.round((cubiertos / total) * 100);
            },

            getAlertas: (progId) => {
                const prog = get().programaciones.find(p => p.id === progId);
                if (!prog) return [];
                const alertas: string[] = [];
                const vacios = prog.asignaciones.filter(a => !a.vigilanteId).length;
                if (vacios > 0) alertas.push(`${vacios} turnos vac├¡os`);
                return alertas;
            },

            fetchProgramacionById: async (progId: string) => {
                const { data: r } = await supabase.from('programacion_mensual').select('*').eq('id', progId).single();
                if (!r) return null;
                await get().fetchProgramacionDetalles(progId);
                return get().programaciones.find(p => p.id === progId) || null;
            },

            setSelectedProgId: (id: string | null) => {
                set({ selectedProgId: id });
                if (id) {
                    get().fetchProgramacionDetalles(id);
                }
            },
            diasTrabajoMap: new Map<string, number>(),

            // Re-calcular el mapa de acceso r├ípido cada vez que cambien las programaciones
            getBusyDays: (vid: string, anio: number, mes: number): Set<number> => {
                return get()._busyMap?.get(`${vid}-${anio}-${mes}`) || new Set();
            },

            _updateMap: () => {
                const progs = get().programaciones;
                const newMap = new Map<string, any>();
                const newBusyMap = new Map<string, Set<number>>();

                progs.forEach(p => {
                    // CORRECCI├ôN: Indexar por puestoId tal como est├í + por UUID traducido
                    // para que getProgramacionRapid encuentre el registro sin importar
                    // si la llamada usa shorthand (MED-0001) o UUID
                    newMap.set(`${p.puestoId}-${p.anio}-${p.mes}`, p);
                    newMap.set(`${p.id}`, p);

                    const dbUuid = translatePuestoToUuid(p.puestoId);
                    if (dbUuid && dbUuid !== p.puestoId) {
                        newMap.set(`${dbUuid}-${p.anio}-${p.mes}`, p);
                    }

                    // Track busy days (usando ambas formas del vigilanteId)
                    if (p.asignaciones) {
                        p.asignaciones.forEach(asig => {
                            if (asig.vigilanteId && asig.jornada !== 'sin_asignar') {
                                const key = `${asig.vigilanteId}-${p.anio}-${p.mes}`;
                                if (!newBusyMap.has(key)) newBusyMap.set(key, new Set());
                                newBusyMap.get(key)!.add(asig.dia);
                            }
                        });
                    }
                });
                set({ _progMap: newMap, _busyMap: newBusyMap } as any);
            },
        })
);

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { supabase, EMPRESA_ID } from '../lib/supabase';
import { showTacticalToast } from '../utils/tacticalToast';
import { useVigilanteStore } from './vigilanteStore';
import { useAuthStore } from './authStore';

export interface TurnoVigilante {
    vigilanteId: string;
    horaInicio: string;
    horaFin: string;
    dia?: string;
}

export interface HistorialPuesto {
    id: string;
    timestamp: string;
    action: 'creacion' | 'asignacion' | 'remocion' | 'cambio' | 'cobertura';
    vigilanteId?: string;
    details: string;
}

export interface TurnoConfig {
    id: string;
    nombre: string;
    inicio: string;
    fin: string;
    color?: string;
}

export interface JornadaCustom {
    id: string;
    nombre: string;
    short: string;
    color: string;
    textColor: string;
}

export interface Puesto {
    id: string;       // MED-0001 format (maps to "codigo" in DB)
    dbId?: string;     // UUID from Supabase
    nombre: string;
    tipo: 'hospital' | 'comando' | 'torre' | 'edificio' | 'retail' | 'logistica' | 'banco' | 'puerto';
    lat: number;
    lng: number;
    elevacion: number;
    estado: 'cubierto' | 'alerta' | 'desprotegido';
    fechaRegistro: string;
    turnos: TurnoVigilante[];
    historial: HistorialPuesto[];
    coberturas?: string[];
    contacto?: string;
    telefono?: string;
    requisitos?: string;
    instrucciones?: string;
    prioridad?: 'baja' | 'media' | 'alta' | 'critica';
    numeroContrato?: string;
    cliente?: string;
    tipoServicio?: string;
    direccion?: string;
    conArmamento?: boolean;
    turnosConfig?: TurnoConfig[];
    jornadasCustom?: JornadaCustom[];
    plantillaRecurrente?: {
        activa: boolean;
        asignaciones: import('./programacionStore').AsignacionDia[];
        personal: import('./programacionStore').PersonalPuesto[];
        desdeAnio: number;
        desMes: number;
    } | null;
}

interface PuestoState {
    puestos: Puesto[];
    nextIdNumber: number;
    loaded: boolean;

    fetchPuestos: () => Promise<void>;
    addPuesto: (
        nombre: string,
        tipo: Puesto['tipo'],
        lat: number,
        lng: number,
        elevacion?: number,
        detalles?: {
            contacto?: string;
            telefono?: string;
            requisitos?: string;
            instrucciones?: string;
            prioridad?: Puesto['prioridad'];
            coberturas?: string[];
            numeroContrato?: string;
            cliente?: string;
            tipoServicio?: string;
            direccion?: string;
            conArmamento?: boolean;
        }
    ) => Promise<string>;
    updatePuestoStatus: (id: string, estado: Puesto['estado']) => void;
    deletePuesto: (id: string) => void;
    updatePuesto: (id: string, changes: Partial<Pick<Puesto, 'turnosConfig'|'jornadasCustom'|'plantillaRecurrente'|'nombre'|'contacto'|'telefono'|'requisitos'|'instrucciones'|'prioridad'|'numeroContrato'|'cliente'|'tipoServicio'|'direccion'|'conArmamento'>>) => void;

    assignGuard: (puestoId: string, vigilanteId: string, horaInicio: string, horaFin: string) => void;
    removeGuard: (puestoId: string, vigilanteId: string, reason?: string) => void;

    getCobertura24Horas: (puestoId: string) => { completa: boolean; huecos: string[] };
    verificarCoberturaTotal: () => { puestosDesprotegidos: Puesto[] };
}

// Nota: el estado de un puesto se calcula din├ímicamente al cargarlo
// (cubierto si tiene turnos activos, desprotegido si no)

export const usePuestoStore = create<PuestoState>()(
    (set, get) => ({
            puestos: [],
            nextIdNumber: 1,
            loaded: false,

            fetchPuestos: async () => {
                try {
                    const currentEmpresaId = useAuthStore.getState().empresaId || EMPRESA_ID;

                    let allRows: any[] = [];
                    let from = 0;
                    const BATCH = 1000;

                    while (true) {
                        const { data, error } = await supabase
                            .from('puestos')
                            .select('*')
                            .eq('empresa_id', currentEmpresaId)
                            .range(from, from + BATCH - 1)
                            .eq('estado', 'Activo')
                            .order('codigo', { ascending: true });

                        if (error) {
                            console.error('Error fetching puestos batch:', error);
                            break;
                        }
                        if (!data || data.length === 0) break;

                        allRows = [...allRows, ...data];
                        from += BATCH;
                        if (allRows.length >= 10000) break;
                    }

                    const rows = allRows;
                    if (!rows || rows.length === 0) {
                        set({ puestos: [], loaded: true });
                        return;
                    }


                    // PERFORMANCE CR├ìTICA: Pre-mapear vigilancia para evitar O(n^2) en la traducci├│n de IDs
                    const currentVigilantes = useVigilanteStore.getState().vigilantes;
                    const vigLookup = new Map<string, string>();
                    currentVigilantes.forEach(v => {
                        if (v.dbId) vigLookup.set(v.dbId, v.id);
                        vigLookup.set(v.id, v.id);
                    });

                    const translateVigFromDb = (dbId: string | null) => {
                        if (!dbId) return null;
                        return vigLookup.get(dbId) || dbId;
                    };

                    const puestoIds = rows.map(r => r.id);

                    // LIMITES DE URL: chunkSize seguro para evitar HTTP 414 URI Too Long (~140 UUIDs max en GET)
                    const CHUNK_SIZE = 140;
                    let allTurnos: any[] = [];
                    let allHistorial: any[] = [];

                    for (let i = 0; i < puestoIds.length; i += CHUNK_SIZE) {
                        const chunk = puestoIds.slice(i, i + CHUNK_SIZE);
                        const [turnosRes, histRes] = await Promise.all([
                            supabase.from('turnos_puesto').select('*').in('puesto_id', chunk),
                            supabase.from('historial_puesto').select('*').in('puesto_id', chunk).order('created_at', { ascending: true })
                        ]);

                        if (turnosRes.data) allTurnos = [...allTurnos, ...turnosRes.data];
                        if (histRes.data) allHistorial = [...allHistorial, ...histRes.data];
                    }

                    // Pre-agrupar para evitar .filter() en cada iteraci├│n
                    const turnsByPuestoId = new Map<string, any[]>();
                    allTurnos.forEach(t => {
                        if (!turnsByPuestoId.has(t.puesto_id)) turnsByPuestoId.set(t.puesto_id, []);
                        turnsByPuestoId.get(t.puesto_id)!.push(t);
                    });

                    const histByPuestoId = new Map<string, any[]>();
                    allHistorial.forEach(h => {
                        if (!histByPuestoId.has(h.puesto_id)) histByPuestoId.set(h.puesto_id, []);
                        histByPuestoId.get(h.puesto_id)!.push(h);
                    });

                    const puestos: Puesto[] = rows.map(row => {
                        const turnos = (turnsByPuestoId.get(row.id) || [])
                            .map(t => ({
                                vigilanteId: translateVigFromDb(t.vigilante_id) as string,
                                horaInicio: t.hora_inicio,
                                horaFin: t.hora_fin,
                                dia: t.dia || undefined,
                            }));

                        const historial = (histByPuestoId.get(row.id) || [])
                            .map(h => ({
                                id: h.id,
                                timestamp: h.created_at,
                                action: h.accion as HistorialPuesto['action'],
                                vigilanteId: translateVigFromDb(h.vigilante_id) as string || undefined,
                                details: h.detalles || '',
                            }));

                        return {
                            id: row.codigo,
                            dbId: row.id,
                            nombre: row.nombre,
                            tipo: row.tipo as Puesto['tipo'],
                            lat: parseFloat(row.latitud) || 6.2308,
                            lng: parseFloat(row.longitud) || -75.5667,
                            elevacion: 9.14,
                            estado: turnos.length > 0 ? 'cubierto' as const : 'desprotegido' as const,
                            fechaRegistro: row.created_at,
                            turnos,
                            historial,
                            contacto: row.contacto || undefined,
                            telefono: row.telefono || undefined,
                            requisitos: row.requisitos || undefined,
                            instrucciones: row.instrucciones || undefined,
                            prioridad: (row.prioridad as Puesto['prioridad']) || 'media',
                            numeroContrato: row.numero_contrato || undefined,
                            cliente: row.cliente || undefined,
                            tipoServicio: row.tipo_servicio || undefined,
                            direccion: row.direccion || undefined,
                            conArmamento: row.con_armamento || false,
                            coberturas: [],
                            turnosConfig: row.turnos_config || [],
                            jornadasCustom: row.jornadas_custom || [],
                            plantillaRecurrente: row.plantilla_recurrente || null,
                        };
                    });

                    let maxNum = 0;
                    puestos.forEach(p => {
                        const match = p.id.match(/MED-(\d+)/);
                        if (match) {
                            const num = parseInt(match[1], 10);
                            if (num > maxNum) maxNum = num;
                        }
                    });

                    set({ puestos, nextIdNumber: maxNum + 1, loaded: true });
                } catch (err) {
                    console.error('Error in fetchPuestos:', err);
                    set({ loaded: true });
                }
            },

            addPuesto: async (nombre, tipo, lat, lng, elevacion, detalles) => {
                try {
                    const currentEmpresaId = useAuthStore.getState().empresaId || EMPRESA_ID;
                    const { data: inserted, error } = await supabase
                        .from('puestos')
                        .insert({
                            empresa_id: currentEmpresaId,
                            nombre,
                            tipo,
                            latitud: lat,
                            longitud: lng,
                            contacto: detalles?.contacto || null,
                            telefono: detalles?.telefono || null,
                            requisitos: detalles?.requisitos || null,
                            instrucciones: detalles?.instrucciones || null,
                            prioridad: detalles?.prioridad || 'media',
                            numero_contrato: detalles?.numeroContrato || null,
                            cliente: detalles?.cliente || null,
                            tipo_servicio: detalles?.tipoServicio || null,
                            direccion: detalles?.direccion || null,
                            con_armamento: detalles?.conArmamento || false,
                        })
                        .select()
                        .single();

                    if (error) {
                        console.error('Error inserting puesto:', error);
                        showTacticalToast({ title: 'Error', message: `No se pudo crear el puesto: ${error.message}`, type: 'error' });
                        return '';
                    }

                    const codigo = inserted.codigo;
                    const { useAuditStore } = await import('./auditStore');
                    useAuditStore.getState().logAction('PUESTOS', 'Nuevo Puesto', `Puesto ${codigo} (${nombre}) registrado en red.`, 'success');

                    await supabase.from('historial_puesto').insert({
                        puesto_id: inserted.id,
                        accion: 'creacion',
                        detalles: `Puesto ${nombre} creado en el sistema`,
                    });

                    await get().fetchPuestos();

                    showTacticalToast({ title: 'Puesto Registrado', message: `Nodo ${codigo} activado en la red operativa.`, type: 'success' });
                    return codigo;
                } catch (err) {
                    console.error('Error adding puesto:', err);
                    showTacticalToast({ title: 'Error', message: 'Error de conexion al crear puesto.', type: 'error' });
                    return '';
                }
            },

            updatePuestoStatus: async (id, estado) => {
                const puesto = get().puestos.find(p => p.id === id);

                set((state) => ({
                    puestos: state.puestos.map((p) =>
                        p.id === id
                            ? {
                                ...p,
                                estado,
                                historial: [
                                    ...(p.historial || []),
                                    { id: crypto.randomUUID(), timestamp: new Date().toISOString(), action: 'cambio' as const, details: `Estado cambiado a: ${estado.toUpperCase()}` }
                                ]
                            } : p
                    )
                }));

                if (puesto?.dbId) {
                    await supabase.from('historial_puesto').insert({
                        puesto_id: puesto.dbId,
                        accion: 'cambio',
                        detalles: `Estado cambiado a: ${estado.toUpperCase()}`,
                    });
                }
            },

            deletePuesto: async (id) => {
                const puesto = get().puestos.find(p => p.id === id);

                set((state) => ({
                    puestos: state.puestos.filter((p) => p.id !== id)
                }));

                if (puesto?.dbId) {
                    await supabase.from('puestos').update({ estado: 'Inactivo' }).eq('id', puesto.dbId);
                }

                showTacticalToast({ title: 'Puesto Removido', message: 'Nodo desactivado y eliminado del sistema.', type: 'warning' });
            },

            updatePuesto: async (id, changes) => {
                const puesto = get().puestos.find(p => p.id === id || p.dbId === id);

                set((state) => ({
                    puestos: state.puestos.map(p => (p.id === id || p.dbId === id) ? { ...p, ...changes } : p)
                }));

                if (puesto?.dbId) {
                    const dbUpdates: Record<string, any> = {};
                    if (changes.nombre !== undefined) dbUpdates.nombre = changes.nombre;
                    if (changes.contacto !== undefined) dbUpdates.contacto = changes.contacto;
                    if (changes.telefono !== undefined) dbUpdates.telefono = changes.telefono;
                    if (changes.requisitos !== undefined) dbUpdates.requisitos = changes.requisitos;
                    if (changes.instrucciones !== undefined) dbUpdates.instrucciones = changes.instrucciones;
                    if (changes.prioridad !== undefined) dbUpdates.prioridad = changes.prioridad;
                    if (changes.numeroContrato !== undefined) dbUpdates.numero_contrato = changes.numeroContrato;
                    if (changes.cliente !== undefined) dbUpdates.cliente = changes.cliente;
                    if (changes.tipoServicio !== undefined) dbUpdates.tipo_servicio = changes.tipoServicio;
                    if (changes.direccion !== undefined) dbUpdates.direccion = changes.direccion;
                    if (changes.conArmamento !== undefined) dbUpdates.con_armamento = changes.conArmamento;
                    if (changes.turnosConfig !== undefined) dbUpdates.turnos_config = changes.turnosConfig;
                    if (changes.jornadasCustom !== undefined) dbUpdates.jornadas_custom = changes.jornadasCustom;
                    if (changes.plantillaRecurrente !== undefined) dbUpdates.plantilla_recurrente = changes.plantillaRecurrente;

                    if (Object.keys(dbUpdates).length > 0) {
                        const { useAuditStore } = await import('./auditStore');
                        useAuditStore.getState().logAction('PUESTOS', 'Edicion Puesto', `Actualizacion de parametros para el puesto ${id}.`, 'info');
                        await supabase.from('puestos').update(dbUpdates).eq('id', puesto.dbId);
                    }
                }
            },

            assignGuard: async (puestoId, vigilanteId, horaInicio, horaFin) => {
                if (horaInicio >= horaFin) {
                    showTacticalToast({ title: 'Inconsistencia de Tiempo', message: 'La hora de inicio debe ser cronologicamente anterior a la de fin.', type: 'error' });
                    return;
                }

                // Helper: translate HID to UUID
                const translateVigToUuid = (id: string | null): string | null => {
                    if (!id) return null;
                    if (id.length > 20) return id;
                    const v = useVigilanteStore.getState().vigilantes.find(vg => vg.id === id);
                    return v?.dbId || id;
                };

                const translatePuestoToUuid = (id: string | null): string | null => {
                    if (!id) return null;
                    if (id.length > 20) return id;
                    const p = get().puestos.find(px => px.id === id);
                    return p?.dbId || id;
                };

                const puesto = get().puestos.find(p => p.id === puestoId);

                // Validate overlap
                const isInvalid = get().puestos.some(p =>
                    p.turnos.some(t => {
                        const isSameGuardOtherPost = t.vigilanteId === vigilanteId && p.id !== puestoId;
                        const isOtherGuardSamePost = t.vigilanteId !== vigilanteId && p.id === puestoId;
                        if ((isSameGuardOtherPost || isOtherGuardSamePost) && (horaInicio < t.horaFin && t.horaInicio < horaFin)) return true;
                        return false;
                    })
                );

                if (isInvalid) {
                    showTacticalToast({ title: 'Conflicto TACTICO', message: 'Solapamiento de horarios detectado en la red de efectivos.', type: 'error' });
                    return;
                }

                const wasAssigned = puesto?.turnos.some(t => t.vigilanteId === vigilanteId);

                // Optimistic
                set((state) => ({
                    puestos: state.puestos.map((p) => {
                        if (p.id !== puestoId) return p;
                        const exists = p.turnos.find(t => t.vigilanteId === vigilanteId);
                        if (exists) {
                            return {
                                ...p,
                                turnos: p.turnos.map(t => t.vigilanteId === vigilanteId ? { ...t, horaInicio, horaFin } : t),
                                historial: [...(p.historial || []), { id: crypto.randomUUID(), timestamp: new Date().toISOString(), action: 'cambio' as const, vigilanteId, details: `Horario modificado: ${horaInicio} - ${horaFin}` }]
                            };
                        }
                        return {
                            ...p,
                            turnos: [...(p.turnos || []), { vigilanteId, horaInicio, horaFin }],
                            historial: [...(p.historial || []), { id: crypto.randomUUID(), timestamp: new Date().toISOString(), action: 'asignacion' as const, vigilanteId, details: `Nuevo vigilante asignado: ${horaInicio} - ${horaFin}` }]
                        };
                    })
                }));

                // Supabase sync
                const dbPuestoId = translatePuestoToUuid(puestoId);
                const dbVigilanteId = translateVigToUuid(vigilanteId);

                if (dbPuestoId && dbVigilanteId) {
                    const currentEmpresaId = useAuthStore.getState().empresaId || EMPRESA_ID;
                    if (wasAssigned) {
                        await supabase.from('turnos_puesto')
                            .update({ hora_inicio: horaInicio, hora_fin: horaFin })
                            .eq('puesto_id', dbPuestoId)
                            .eq('vigilante_id', dbVigilanteId);
                    } else {
                        await supabase.from('turnos_puesto').insert({
                            empresa_id: currentEmpresaId,
                            puesto_id: dbPuestoId,
                            vigilante_id: dbVigilanteId,
                            hora_inicio: horaInicio,
                            hora_fin: horaFin,
                        });
                    }
                    await supabase.from('historial_puesto').insert({
                        puesto_id: dbPuestoId,
                        accion: wasAssigned ? 'cambio' : 'asignacion',
                        vigilante_id: dbVigilanteId,
                        detalles: wasAssigned ? `Horario modificado: ${horaInicio} - ${horaFin}` : `Nuevo vigilante asignado: ${horaInicio} - ${horaFin}`,
                    });
                    const { useAuditStore } = await import('./auditStore');
                    useAuditStore.getState().logAction('PUESTOS', wasAssigned ? 'Modificacion Turno' : 'Asignacion Turno', `${wasAssigned ? 'Modificado' : 'Asignado'} vigilante ${vigilanteId} al puesto ${puestoId}.`, 'info');
                }

                showTacticalToast({
                    title: wasAssigned ? 'Horario Modificado' : 'Efectivo Desplegado',
                    message: wasAssigned ? 'Cronograma actualizado para el puesto.' : 'Nuevo vigilante incorporado a la linea.',
                    type: 'success'
                });
            },

            removeGuard: async (puestoId, vigilanteId, reason = 'Removido por operador') => {
                const puesto = get().puestos.find(p => p.id === puestoId);

                set((state) => ({
                    puestos: state.puestos.map((p) =>
                        p.id === puestoId
                            ? {
                                ...p,
                                turnos: (p.turnos || []).filter(t => t.vigilanteId !== vigilanteId),
                                historial: [...(p.historial || []), { id: crypto.randomUUID(), timestamp: new Date().toISOString(), action: 'remocion' as const, vigilanteId, details: reason }]
                            } : p
                    )
                }));

                // Helper local (already defined in assignGuard scope, but this is a different method)
                const vigUuId = useVigilanteStore.getState().vigilantes.find(vg => vg.id === vigilanteId)?.dbId || vigilanteId;

                if (puesto?.dbId) {
                    await supabase.from('turnos_puesto')
                        .delete()
                        .eq('puesto_id', puesto.dbId)
                        .eq('vigilante_id', vigUuId);

                    await supabase.from('historial_puesto').insert({
                        puesto_id: puesto.dbId,
                        accion: 'remocion',
                        vigilante_id: vigUuId,
                        detalles: reason,
                    });
                }

                showTacticalToast({ title: 'Efectivo Retirado', message: 'El vigilante ha sido removido de su posicion actual.', type: 'info' });
            },

            getCobertura24Horas: (puestoId) => {
                const puesto = get().puestos.find(p => p.id === puestoId);
                if (!puesto || !puesto.turnos || puesto.turnos.length === 0) {
                    return { completa: false, huecos: ['00:00 - 24:00'] };
                }

                // Usamos un array de 48 slots (cada 30 min) para representar las 24h
                const slots = new Uint8Array(48); // 0 = vac├¡o, 1 = cubierto

                puesto.turnos.forEach(turno => {
                    const [hI, mI] = turno.horaInicio.split(':').map(Number);
                    const [hF, mF] = turno.horaFin.split(':').map(Number);

                    const startSlot = hI * 2 + (mI >= 30 ? 1 : 0);
                    const endSlot = hF * 2 + (mF >= 30 ? 1 : 0);

                    // Manejo de turnos que cruzan la medianoche
                    if (startSlot < endSlot) {
                        for (let i = startSlot; i < endSlot; i++) slots[i] = 1;
                    } else if (startSlot > endSlot) {
                        // Turno de noche (ej: 22:00 a 06:00)
                        for (let i = startSlot; i < 48; i++) slots[i] = 1;
                        for (let i = 0; i < endSlot; i++) slots[i] = 1;
                    }
                });

                const huecos: string[] = [];
                let inGap = false;
                let gapStart = 0;

                for (let i = 0; i <= 48; i++) {
                    const isCovered = i < 48 ? slots[i] === 1 : true; // Cierre virtual al final

                    if (!isCovered && !inGap) {
                        inGap = true;
                        gapStart = i;
                    } else if (isCovered && inGap) {
                        inGap = false;
                        const hS = Math.floor(gapStart / 2).toString().padStart(2, '0');
                        const mS = (gapStart % 2 === 0 ? '00' : '30');
                        const hE = Math.floor(i / 2).toString().padStart(2, '0');
                        const mE = (i % 2 === 0 ? '00' : '30');
                        huecos.push(`${hS}:${mS} - ${hE}:${mE}`);
                    }
                }

                return { completa: huecos.length === 0, huecos };
            },

            verificarCoberturaTotal: () => {
                const puestos = get().puestos;
                const desprotegidos = puestos.filter(p => {
                    const cobertura = get().getCobertura24Horas(p.id);
                    return !cobertura.completa;
                });
                return { puestosDesprotegidos: desprotegidos };
            }
        })
);

import { useEffect, useRef } from 'react';
import { usePuestoStore } from './puestoStore';
import { useVigilanteStore } from './vigilanteStore';
import { useProgramacionStore } from './programacionStore';
import { useAIStore } from './aiStore';

export const useMotorInteligencia = () => {
    const puestos = usePuestoStore(s => s.puestos);
    const vigilantes = useVigilanteStore(s => s.vigilantes);
    const programaciones = useProgramacionStore(s => s.programaciones);
    const addAction = useAIStore(s => s.addAction);
    const actions = useAIStore(s => s.actions);

    // Guardar logs que ya alertamos para no hacer spam (en memoria ram mientras la app esta abierta)
    const alertasEmitidas = useRef<Set<string>>(new Set());

    useEffect(() => {
        // Ejecutar analisis cada vez que cambie algo, pero con un pequeno debounce tactico
        const timer = setTimeout(() => {
            analizarSistema();
        }, 3000); // 3 segundos despues del cambio

        return () => clearTimeout(timer);
    }, [puestos, vigilantes, programaciones]);

    const dispararAlerta = (id: string, texto: string, priority: 'high' | 'medium' | 'low') => {
        if (alertasEmitidas.current.has(id)) return;

        // Cooldown dinamico basado en prioridad (Mas estricto para no saturar)
        const now = Date.now();
        // High: 1 hora (critico). Medium: 8 horas. Low: 24 horas (una vez al dia).
        const cooldown = priority === 'high' ? 1000 * 60 * 60 : priority === 'medium' ? 1000 * 60 * 60 * 8 : 1000 * 60 * 60 * 24;

        const yaExiste = actions.some(a => 
            (a.text === texto || a.id.split('_')[0] === id.split('_')[0]) && 
            (now - a.timestamp) < cooldown
        );

        if (yaExiste) return;

        addAction({
            text: texto,
            type: 'notification',
            sender: 'ai',
            priority
        });
        alertasEmitidas.current.add(id);
    };

    const analizarSistema = () => {
        if (!puestos || !Array.isArray(puestos)) return;
        if (!vigilantes || !Array.isArray(vigilantes)) return;
        if (!programaciones || !Array.isArray(programaciones)) return;

        const mesActual = new Date().getMonth();
        const anioActual = new Date().getFullYear();
        const hoy = new Date().getDate();

        // --- 1. COBERTURA DE PUESTOS (ALTA CRITICIDAD) ---
        const puestosIncompletos = puestos.filter(p => {
            const vigis = vigilantes.filter(v => 
                v.puestoId === p.dbId || v.puestoId === p.id
            ); // Compare UUID or Shorthand
            return vigis.length < 3;
        });

        if (puestosIncompletos.length > 0) {
            // Solo alertar si el deficit es significativo (> 20% de los puestos) o si es un solo puesto critico
            if (puestosIncompletos.length === 1) {
                dispararAlerta(
                    `deficit_puesto_${puestosIncompletos[0].id}`,
                    `**REPORTE DE CORAZAI:** El puesto "${puestosIncompletos[0].nombre}" esta incompleto. Como supervisor de programacion, noto que falta personal para garantizar la seguridad total.`,
                    'high'
                );
            } else if (puestosIncompletos.length > 3) {
                dispararAlerta(
                    `deficit_puestos_masivo`,
                    `**ALERTA DE PROGRAMACION:** Detecto un fallo sistemico. ${puestosIncompletos.length} puestos tienen huecos en sus cuadrantes. CorazAI recomienda reasignar personal disponible inmediatamente.`,
                    'high'
                );
            }
        }

        // --- 2. FALLAS OPERATIVAS (AUSENTISMO EN TIEMPO REAL) ---
        const ausentes = vigilantes.filter(v => v.puestoId && v.estado === 'ausente');
        if (ausentes.length > 0) {
            if (ausentes.length <= 2) {
                ausentes.forEach(v => {
                    const puesto = puestos.find(p => p.dbId === v.puestoId); // Compare UUID
                    dispararAlerta(
                        `ausente_${v.id}`,
                        `**NOVEDAD OPERATIVA:** CorazAI informa que ${v.nombre} esta ausente en "${puesto?.nombre || 'Puesto'}". Esto afecta mi planificacion de turnos.`,
                        'high'
                    );
                });
            } else {
                dispararAlerta(
                    `ausentes_multiples`,
                    `**CRISIS DE COBERTURA:** Tengo ${ausentes.length} ausencias reportadas. CorazAI esta analizando el impacto en la programacion mensual.`,
                    'high'
                );
            }
        }

        // --- 3. PROGRAMACION (TRABAJO ADMINISTRATIVO - MENOS INTRUSIVO) ---
        const progsMes = programaciones.filter(p => p.anio === anioActual && p.mes === mesActual);
        const puestosSinProg = puestos.filter(p => !progsMes.some(prog => prog.puestoId === p.dbId)); // Use UUID

        if (puestosSinProg.length > 0) {
            // Solo es urgente si falta poco para acabar el mes o si son Demasiados puestos
            const esUrgente = hoy > 25 || puestosSinProg.length > (puestos.length / 2);

            if (esUrgente) {
                dispararAlerta(
                    `sin_prog_critical`,
                    `**URGENCIA CORAZAI:** ${puestosSinProg.length} puestos carecen de programacion oficial para este mes. CorazAI exige regularizar estos cuadrantes.`,
                    'high'
                );
            } else if (hoy > 15 && puestosSinProg.length > 0) {
                // Notificacion de media prioridad solo a mitad de mes
                dispararAlerta(
                    `sin_prog_advice`,
                    `**MONITOREO PREVENTIVO:** CorazAI ha detectado que faltan ${puestosSinProg.length} cuadrantes. Sugiero iniciar la programacion para evitar cuellos de botella.`,
                    'medium'
                );
            }
        }

        // --- 4. TRAMITES (ESTADISTICAS SILENCIOSAS) ---
        const borradoresCount = progsMes.filter(p => p.estado === 'borrador').length;
        if (borradoresCount > 5) { // Solo avisar si hay una acumulacion real
            dispararAlerta(
                `borradores_acumulados`,
                `**FLUJO DE TRABAJO:** Tienes ${borradoresCount} programaciones en borrador. Considere publicarlas para formalizar la operacion.`,
                'low'
            );
        }

        const vigAsigs = new Map<string, { p: any, a: any }[]>();
        progsMes.forEach(p => {
            (p.asignaciones || []).forEach(a => {
                const vid = a.vigilanteId;
                if (!vid) return; 
                if (!vigAsigs.has(vid)) vigAsigs.set(vid, []);
                vigAsigs.get(vid)!.push({ p, a });
            });
        });

        // --- 5. ANALISIS PREDICTIVO (AGOTAMIENTO Y FATIGA) ---
        vigilantes.forEach(v => {
            const currentAsigs = [...(vigAsigs.get(v.dbId || '') || []), ...(vigAsigs.get(v.id) || [])];
            if (currentAsigs.length === 0) return;

            const diasTotales = currentAsigs.filter(x => x.a.jornada === 'normal').length;
            if (diasTotales > 20) {
                dispararAlerta(
                    `exceso_horas_${v.id}`,
                    `**ALERTA PREDICTIVA:** ${v.nombre} ha superado los 20 turnos este mes (${diasTotales * 12} horas). Detecto riesgo de fatiga cronica que pondra en peligro la seguridad del puesto. CorazAI sugiere descanso inmediato.`,
                    'high'
                );
            } else if (diasTotales > 17) {
                dispararAlerta(
                    `limite_horas_${v.id}`,
                    `**INSIGHT OPERATIVO:** ${v.nombre} se acerca al limite legal de horas. Recomiendo no asignar mas turnos extras para este vigilante.`,
                    'medium'
                );
            }

            // b. DIAs consecutivos (Fatiga acumulada)
            // Agrupamos todas sus asignaciones del mes y las ordenamos por dia
            const todasAsigs = currentAsigs.map(x => x.a).sort((a: any, b: any) => a.dia - b.dia);

            let consecutivos = 0;
            let maxConsecutivos = 0;

            todasAsigs.forEach((asig: any) => {
                if (asig.jornada === 'normal') {
                    consecutivos++;
                    if (consecutivos > maxConsecutivos) maxConsecutivos = consecutivos;
                } else {
                    consecutivos = 0;
                }
            });

            if (maxConsecutivos >= 6) {
                dispararAlerta(
                    `consecutivos_critico_${v.id}`,
                    `**ALERTA DE SEGURIDAD:** ${v.nombre} lleva ${maxConsecutivos} dias seguidos trabajando sin descanso. Mi analisis predice una caida en su capacidad de alerta tactica. Exijo programar un dia de descanso.`,
                    'high'
                );
            }
        });
    };

    return null; 
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { supabase, EMPRESA_ID } from '../lib/supabase';
import { showTacticalToast } from '../utils/tacticalToast';
import { useAuthStore } from './authStore';

export interface GuardHistory {
    id: string;
    timestamp: string;
    action: string;
    details: string;
}

export interface Descargo {
    id: string;
    puestoId?: string;
    puestoNombre?: string;
    fecha: string;
    descripcion: string;
    tipo: 'disciplinario' | 'incidente' | 'queja' | 'administrativo';
    estado: 'activo' | 'resuelto';
}

export interface Vigilante {
    id: string; // C-0001 format (maps to "codigo" in DB)
    dbId?: string; // UUID from Supabase
    nombre: string;
    cedula: string;
    rango: string;
    estado: 'disponible' | 'activo' | 'ausente';
    foto?: string;
    puestoId?: string;
    fechaIngreso: string;
    historial: GuardHistory[];
    justificacionDisponible?: string;
    descargos: Descargo[];
    vacaciones?: {
        inicio: string;
        fin: string;
        motivo?: string;
    };
    telefono?: string;
    email?: string;
    especialidad?: string;
}

interface VigilanteState {
    vigilantes: Vigilante[];
    nextIdNumber: number;
    loaded: boolean;

    // Actions
    fetchVigilantes: () => Promise<void>;
    addVigilante: (
        nombre: string,
        cedula: string,
        rango: string,
        modulo: 'activo' | 'disponible',
        justificacion?: string,
        assignment?: { puestoId: string; horaInicio: string; horaFin: string }
    ) => Promise<string>;
    updateGuardStatus: (id: string, estado: Vigilante['estado'], puestoId?: string, justificacion?: string) => void;
    addActivity: (id: string, action: string, details: string) => void;
    deleteVigilante: (id: string) => void;
    addDescargo: (vigilanteId: string, descargo: Omit<Descargo, 'id'>) => void;
    resolverDescargo: (vigilanteId: string, descargoId: string) => void;
    setVacaciones: (vigilanteId: string, inicio: string, fin: string, motivo?: string) => void;
    cancelarVacaciones: (vigilanteId: string) => void;
    updateVigilante: (id: string, updates: Partial<Pick<Vigilante, 'nombre' | 'cedula' | 'rango' | 'foto' | 'telefono' | 'email' | 'especialidad'>>) => void;
    tieneDescargoEnPuesto: (vigilanteId: string, puestoId: string) => boolean;
}

// Helper: Map DB row ÔåÆ Vigilante
function mapDbToVigilante(row: any, historial: any[], descargos: any[], vacacion: any): Vigilante {
    return {
        id: row.codigo,
        dbId: row.id,
        nombre: `${row.nombres} ${row.apellidos}`.trim(),
        cedula: row.cedula,
        rango: row.rango || 'Vigilante',
        estado: row.estado as Vigilante['estado'],
        foto: row.foto_url || undefined,
        puestoId: row.puesto_actual_id || undefined,
        fechaIngreso: row.fecha_ingreso || row.created_at,
        justificacionDisponible: row.justificacion_disponible || undefined,
        telefono: row.telefono || undefined,
        email: row.email || undefined,
        especialidad: row.especialidad || undefined,
        historial: (historial || []).map((h: any) => ({
            id: h.id,
            timestamp: h.created_at,
            action: h.accion,
            details: h.detalles || '',
        })),
        descargos: (descargos || []).map((d: any) => ({
            id: d.id,
            puestoId: d.puesto_id || undefined,
            puestoNombre: d.puesto_nombre || undefined,
            fecha: d.fecha,
            descripcion: d.descripcion,
            tipo: d.tipo,
            estado: d.estado,
        })),
        vacaciones: vacacion ? {
            inicio: vacacion.fecha_inicio,
            fin: vacacion.fecha_fin,
            motivo: vacacion.motivo || undefined,
        } : undefined,
    };
}

export const useVigilanteStore = create<VigilanteState>()(
    (set, get) => ({
            vigilantes: [],
            nextIdNumber: 1,
            loaded: false,

            fetchVigilantes: async () => {
                try {
                    const currentEmpresaId = useAuthStore.getState().empresaId || EMPRESA_ID;

                    // 1. CARGA R├üPIDA: Primero obtenemos el conteo o estimaci├│n para paralelizar
                    const { count, error: countErr } = await supabase
                        .from('vigilantes')
                        .select('*', { count: 'exact', head: true })
                        .eq('empresa_id', currentEmpresaId);

                    if (countErr) throw countErr;

                    const totalRecords = count || 0;
                    const BATCH = 1000;
                    const fetchPromises = [];

                    for (let from = 0; from < totalRecords; from += BATCH) {
                        fetchPromises.push(
                            supabase
                                .from('vigilantes')
                                .select('*')
                                .eq('empresa_id', currentEmpresaId)
                                .range(from, from + BATCH - 1)
                        );
                    }

                    const results = await Promise.all(fetchPromises);
                    let allRows = results.flatMap((r: any) => r.data || []);

                    if (allRows.length >= 25000) {
                        allRows = allRows.slice(0, 25000);
                    }

                    const rows = allRows;
                    if (rows.length === 0) {
                        set({ vigilantes: [], loaded: true });
                        return;
                    }

                    const vigilanteIds = rows.map(r => r.id);

                    // LIMITES DE URL: chunkSize seguro para evitar HTTP 414 URI Too Long (~140 UUIDs max en GET)
                    // PERFORMANCE CR├ìTICA: Si hay miles de guardias, NO hacer 400 consultas de historial al inicio.
                    const CHUNK_SIZE = 140;
                    let allHistorial: any[] = [];
                    let allDescargos: any[] = [];
                    let allVacaciones: any[] = [];

                    if (vigilanteIds.length <= 1500) {
                        for (let i = 0; i < vigilanteIds.length; i += CHUNK_SIZE) {
                            const chunk = vigilanteIds.slice(i, i + CHUNK_SIZE);

                            const [histRes, descRes, vacRes] = await Promise.all([
                                supabase.from('historial_vigilante').select('*').in('vigilante_id', chunk).order('created_at', { ascending: true }),
                                supabase.from('descargos').select('*').in('vigilante_id', chunk),
                                supabase.from('vacaciones').select('*').in('vigilante_id', chunk).eq('estado', 'aprobado')
                            ]);

                            if (histRes.data) allHistorial = [...allHistorial, ...histRes.data];
                            if (descRes.data) allDescargos = [...allDescargos, ...descRes.data];
                            if (vacRes.data) allVacaciones = [...allVacaciones, ...vacRes.data];
                        }
                    } else {
                        console.log('[PERFORMANCE] Saltando historial completo por masividad. Se traer├ín en O(1).');
                    }

                    const vigilantes: Vigilante[] = rows.map(row => {
                        const hist = (allHistorial || []).filter(h => h.vigilante_id === row.id);
                        const desc = (allDescargos || []).filter(d => d.vigilante_id === row.id);
                        const vac = (allVacaciones || []).find(v => v.vigilante_id === row.id);
                        return mapDbToVigilante(row, hist, desc, vac);
                    });

                    // Calculate next ID number
                    let maxNum = 0;
                    vigilantes.forEach(v => {
                        const match = v.id.match(/C-(\d+)/);
                        if (match) {
                            const num = parseInt(match[1], 10);
                            if (num > maxNum) maxNum = num;
                        }
                    });

                    set({ vigilantes, nextIdNumber: maxNum + 1, loaded: true });
                } catch (err) {
                    console.error('Error in fetchVigilantes:', err);
                    set({ loaded: true });
                }
            },

            addVigilante: async (nombre, cedula, rango, modulo, justificacion, assignment) => {
                const { useAuditStore } = await import('./auditStore');
                const logAction = useAuditStore.getState().logAction;
                const nameParts = nombre.trim().split(' ');
                const nombres = nameParts.slice(0, Math.ceil(nameParts.length / 2)).join(' ');
                const apellidos = nameParts.slice(Math.ceil(nameParts.length / 2)).join(' ') || nombres;

                try {
                    const currentEmpresaId = useAuthStore.getState().empresaId || EMPRESA_ID;
                    // Insert into Supabase - codigo is auto-generated by trigger
                    const { data: inserted, error } = await supabase
                        .from('vigilantes')
                        .insert({
                            empresa_id: currentEmpresaId,
                            cedula,
                            nombres,
                            apellidos,
                            rango,
                            estado: modulo === 'activo' ? 'activo' : 'disponible',
                            puesto_actual_id: assignment?.puestoId || null,
                            justificacion_disponible: modulo === 'disponible' ? justificacion : null,
                            fecha_ingreso: new Date().toISOString().split('T')[0],
                        })
                        .select()
                        .single();

                    if (error) {
                        console.error('Error inserting vigilante:', error);
                        showTacticalToast({ title: 'Error', message: `No se pudo registrar: ${error.message}`, type: 'error' });
                        return '';
                    }

                    const codigo = inserted.codigo;
                    logAction('VIGILANTES', 'Registro Inicial', `Efectivo ${codigo} (${nombre}) incorporado al sistema.`, 'success');

                    // Insert initial historial
                    await supabase.from('historial_vigilante').insert({
                        vigilante_id: inserted.id,
                        accion: 'Registro Inicial',
                        detalles: `Ingreso al sistema con codigo tactico ${codigo}. Modulo: ${modulo === 'activo' ? 'Vigilantes Activos' : 'Personal Disponible'}`,
                    });

                    // Refresh from DB
                    await get().fetchVigilantes();

                    showTacticalToast({
                        title: 'Efectivo Registrado',
                        message: `Vigilante ${codigo} incorporado exitosamente al modulo de ${modulo === 'activo' ? 'Personal Activo' : 'Personal Disponible'}.`,
                        type: 'success'
                    });
                    return codigo;
                } catch (err) {
                    console.error('Error adding vigilante:', err);
                    showTacticalToast({ title: 'Error', message: 'Error de conexion al registrar vigilante.', type: 'error' });
                    return '';
                }
            },

            updateGuardStatus: async (id, estado, puestoId, justificacion) => {
                const { useAuditStore } = await import('./auditStore');
                const logAction = useAuditStore.getState().logAction;
                const vigilante = get().vigilantes.find(v => v.id === id);
                if (!vigilante?.dbId) return;

                logAction('VIGILANTES', 'Cambio de Estado', `Efectivo ${id} paso a estado ${estado.toUpperCase()}${justificacion ? `. Motivo: ${justificacion}` : ''}`, 'info');

                // Optimistic update
                set((state) => ({
                    vigilantes: state.vigilantes.map((v) =>
                        v.id === id
                            ? {
                                ...v,
                                estado,
                                puestoId: estado === 'disponible' ? undefined : (puestoId !== undefined ? (puestoId || undefined) : v.puestoId),
                                justificacionDisponible: estado === 'disponible' && justificacion ? justificacion : v.justificacionDisponible,
                                historial: [
                                    ...(v.historial || []),
                                    {
                                        id: crypto.randomUUID(),
                                        timestamp: new Date().toISOString(),
                                        action: 'Cambio de Estado',
                                        details: `Transicion a ${estado.toUpperCase()}${puestoId ? ` en puesto ${puestoId}` : ''}${justificacion ? `. Motivo: ${justificacion}` : ''}`
                                    }
                                ]
                            }
                            : v
                    )
                }));

                // Write to Supabase
                await supabase
                    .from('vigilantes')
                    .update({
                        estado,
                        puesto_actual_id: estado === 'disponible' ? null : (puestoId || vigilante.puestoId || null),
                        justificacion_disponible: estado === 'disponible' && justificacion ? justificacion : null,
                    })
                    .eq('id', vigilante.dbId);

                await supabase.from('historial_vigilante').insert({
                    vigilante_id: vigilante.dbId,
                    accion: 'Cambio de Estado',
                    detalles: `Transicion a ${estado.toUpperCase()}${puestoId ? ` en puesto ${puestoId}` : ''}${justificacion ? `. Motivo: ${justificacion}` : ''}`,
                });
            },

            addActivity: async (id, action, details) => {
                const vigilante = get().vigilantes.find(v => v.id === id);

                // Optimistic
                set((state) => ({
                    vigilantes: state.vigilantes.map((v) =>
                        v.id === id
                            ? {
                                ...v,
                                historial: [
                                    ...(v.historial || []),
                                    { id: crypto.randomUUID(), timestamp: new Date().toISOString(), action, details }
                                ]
                            }
                            : v
                    )
                }));

                if (vigilante?.dbId) {
                    await supabase.from('historial_vigilante').insert({
                        vigilante_id: vigilante.dbId,
                        accion: action,
                        detalles: details,
                    });
                }
            },

            deleteVigilante: async (id) => {
                const vigilante = get().vigilantes.find(v => v.id === id);

                // Optimistic
                set((state) => ({
                    vigilantes: state.vigilantes.filter((v) => v.id !== id)
                }));

                if (vigilante?.dbId) {
                    const { useAuditStore } = await import('./auditStore');
                    useAuditStore.getState().logAction('VIGILANTES', 'Baja de Efectivo', `Efectivo ${id} (${vigilante.nombre}) dado de baja del sistema.`, 'warning');

                    await supabase
                        .from('vigilantes')
                        .update({ estado: 'inactivo' })
                        .eq('id', vigilante.dbId);
                }
            },

            addDescargo: async (vigilanteId, descargo) => {
                const vigilante = get().vigilantes.find(v => v.id === vigilanteId);
                const newId = crypto.randomUUID();

                // Optimistic
                set((state) => ({
                    vigilantes: state.vigilantes.map((v) =>
                        v.id === vigilanteId
                            ? {
                                ...v,
                                descargos: [...(v.descargos || []), { ...descargo, id: newId }],
                                historial: [
                                    ...(v.historial || []),
                                    {
                                        id: crypto.randomUUID(),
                                        timestamp: new Date().toISOString(),
                                        action: 'Descargo Registrado',
                                        details: `${descargo.tipo.toUpperCase()}: ${descargo.descripcion}`
                                    }
                                ]
                            }
                            : v
                    )
                }));

                if (vigilante?.dbId) {
                    const currentEmpresaId = useAuthStore.getState().empresaId || EMPRESA_ID;
                    await supabase.from('descargos').insert({
                        empresa_id: currentEmpresaId,
                        vigilante_id: vigilante.dbId,
                        puesto_id: descargo.puestoId || null,
                        puesto_nombre: descargo.puestoNombre || null,
                        fecha: descargo.fecha,
                        descripcion: descargo.descripcion,
                        tipo: descargo.tipo,
                        estado: descargo.estado,
                    });
                    await supabase.from('historial_vigilante').insert({
                        vigilante_id: vigilante.dbId,
                        accion: 'Descargo Registrado',
                        detalles: `${descargo.tipo.toUpperCase()}: ${descargo.descripcion}`,
                    });
                }

                showTacticalToast({ title: 'Descargo Registrado', message: 'Nueva incidencia vinculada al historial del efectivo.', type: 'warning' });
            },

            resolverDescargo: async (vigilanteId, descargoId) => {
                set((state) => ({
                    vigilantes: state.vigilantes.map((v) =>
                        v.id === vigilanteId
                            ? { ...v, descargos: (v.descargos || []).map(d => d.id === descargoId ? { ...d, estado: 'resuelto' as const } : d) }
                            : v
                    )
                }));

                await supabase
                    .from('descargos')
                    .update({ estado: 'resuelto' })
                    .eq('id', descargoId);

                showTacticalToast({ title: 'Caso Resuelto', message: 'El descargo administrativo ha sido marcado como resuelto.', type: 'success' });
            },

            setVacaciones: async (vigilanteId, inicio, fin, motivo) => {
                const vigilante = get().vigilantes.find(v => v.id === vigilanteId);

                set((state) => ({
                    vigilantes: state.vigilantes.map((v) =>
                        v.id === vigilanteId
                            ? {
                                ...v,
                                vacaciones: { inicio, fin, motivo },
                                historial: [
                                    ...(v.historial || []),
                                    { id: crypto.randomUUID(), timestamp: new Date().toISOString(), action: 'Vacaciones Programadas', details: `Del ${inicio} al ${fin}${motivo ? '. ' + motivo : ''}` }
                                ]
                            }
                            : v
                    )
                }));

                if (vigilante?.dbId) {
                    // CORRECCI├ôN: Cancelar vacaciones previas antes de insertar las nuevas
                    // Evita duplicados en la tabla vacaciones
                    await supabase
                        .from('vacaciones')
                        .update({ estado: 'cancelado' })
                        .eq('vigilante_id', vigilante.dbId)
                        .eq('estado', 'aprobado');

                    await supabase.from('vacaciones').insert({
                        vigilante_id: vigilante.dbId,
                        fecha_inicio: inicio,
                        fecha_fin: fin,
                        motivo: motivo || null,
                        estado: 'aprobado',
                    });
                    await supabase.from('historial_vigilante').insert({
                        vigilante_id: vigilante.dbId,
                        accion: 'Vacaciones Programadas',
                        detalles: `Del ${inicio} al ${fin}${motivo ? '. ' + motivo : ''}`,
                    });
                }

                showTacticalToast({ title: 'Licencia Programada', message: `Ciclo de vacaciones registrado para el efectivo ${vigilanteId}.`, type: 'info' });
            },

            cancelarVacaciones: async (vigilanteId) => {
                const vigilante = get().vigilantes.find(v => v.id === vigilanteId);
                set((state) => ({
                    vigilantes: state.vigilantes.map((v) =>
                        v.id === vigilanteId ? { ...v, vacaciones: undefined } : v
                    )
                }));

                if (vigilante?.dbId) {
                    await supabase
                        .from('vacaciones')
                        .update({ estado: 'cancelado' })
                        .eq('vigilante_id', vigilante.dbId)
                        .eq('estado', 'aprobado');
                }
            },

            updateVigilante: async (id, updates) => {
                const { useAuditStore } = await import('./auditStore');
                const logAction = useAuditStore.getState().logAction;
                const vigilante = get().vigilantes.find(v => v.id === id);

                logAction('VIGILANTES', 'Edicion Perfil', `Se actualizaron datos del efectivo ${id} (${vigilante?.nombre}).`, 'info');

                set((state) => ({
                    vigilantes: state.vigilantes.map((v) =>
                        v.id === id
                            ? {
                                ...v,
                                ...updates,
                                historial: [
                                    ...(v.historial || []),
                                    { id: crypto.randomUUID(), timestamp: new Date().toISOString(), action: 'Perfil Actualizado', details: `Se modificaron datos del perfil: ${Object.keys(updates).join(', ')}` }
                                ]
                            }
                            : v
                    )
                }));

                if (vigilante?.dbId) {
                    const dbUpdates: Record<string, any> = {};
                    if (updates.nombre) {
                        const parts = updates.nombre.trim().split(' ');
                        dbUpdates.nombres = parts.slice(0, Math.ceil(parts.length / 2)).join(' ');
                        dbUpdates.apellidos = parts.slice(Math.ceil(parts.length / 2)).join(' ') || dbUpdates.nombres;
                    }
                    if (updates.cedula) dbUpdates.cedula = updates.cedula;
                    if (updates.rango) dbUpdates.rango = updates.rango;
                    if (updates.foto) dbUpdates.foto_url = updates.foto;
                    if (updates.telefono) dbUpdates.telefono = updates.telefono;
                    if (updates.email) dbUpdates.email = updates.email;
                    if (updates.especialidad) dbUpdates.especialidad = updates.especialidad;

                    if (Object.keys(dbUpdates).length > 0) {
                        await supabase.from('vigilantes').update(dbUpdates).eq('id', vigilante.dbId);
                    }
                    await supabase.from('historial_vigilante').insert({
                        vigilante_id: vigilante.dbId,
                        accion: 'Perfil Actualizado',
                        detalles: `Se modificaron datos del perfil: ${Object.keys(updates).join(', ')}`,
                    });
                }

                showTacticalToast({ title: 'Perfil Actualizado', message: 'La informacion del efectivo ha sido modificada correctamente.', type: 'success' });
            },

            tieneDescargoEnPuesto: (vigilanteId, puestoId) => {
                const v = get().vigilantes.find(v => v.id === vigilanteId);
                if (!v) return false;
                return (v.descargos || []).some(
                    d => d.estado === 'activo' && (d.puestoId === puestoId || !d.puestoId)
                );
            }
        })
);

